import{_ as e,o,c as d,R as c}from"./chunks/framework.vN7-ZgWj.js";const m=JSON.parse('{"title":"新概念英语第一册学习笔记","description":"新概念英语第一册学习笔记","frontmatter":{"title":"新概念英语第一册学习笔记","head":[["meta",{"name":"description","content":"新概念英语第一册学习笔记"}],["meta",{"name":"keywords","content":"新概念英语 第一册 学习笔记 nce note"}]]},"headers":[],"relativePath":"language/english/nce/one.md","filePath":"language/english/nce/one.md","lastUpdated":1715012799000}'),t={name:"language/english/nce/one.md"},s=c('<h2 id="总结" tabindex="-1">总结 <a class="header-anchor" href="#总结" aria-label="Permalink to &quot;总结&quot;">​</a></h2><div class="tip custom-block"><p class="custom-block-title">✨新概念英语第一册主要知识点快速索引</p><p><strong>时态</strong>：<a href="#lesson-31-32">现在进行时</a>、<a href="#lesson-47-48">一般现在时非三单</a>、<a href="#lesson-49-50">一般现在时三单</a>、<a href="#lesson-37-38">一般将来时①</a>、<a href="#lesson-91-92">一般将来时②</a>、<a href="#lesson-67-68">一般过去时①</a>、<a href="#lesson-71-72">一般过去时②</a>、<a href="#lesson-83-84">现在完成时①</a>、<a href="#lesson-89-90">现在完成时②</a>、<a href="#lesson-117-118">过去进行时</a>、<a href="#lesson-119-120">过去完成时</a></p><p><a href="#lesson-19-20"><strong>There be结构</strong></a></p><p><a href="#lesson-141-142"><strong>被动语态</strong></a></p><p><strong>问句</strong>：<a href="#lesson-1-2">一般疑问句</a>、<a href="#lesson-5-6">选择疑问句</a>、<a href="#lesson-7-8">特殊疑问句</a>、<a href="#lesson-67-68">否定疑问句</a>、<a href="#lesson-101-102">反意疑问句</a></p><p><strong>从句</strong>：<a href="#lesson-75-76">陈述句宾语从句</a>、<a href="#lesson-139-140">疑问句宾语从句</a>、<a href="#lesson-121-122">定语从句①</a>、<a href="#lesson-123-124">定语从句②</a>、<a href="#lesson-117-118">时间状语从句</a>、<a href="#lesson-137-138">条件状语从句</a></p><p><strong>倒装句</strong>：<a href="#lesson-113-114">so和neither倒装句</a></p><p><strong>引语</strong>：<a href="#lesson-99-100">直接引语和间接引语</a>、<a href="#lesson-133-134">引语的时态和人称变化</a>、<a href="#lesson-135-136">引语的情态动词变化</a></p><p><strong>名词</strong>：<a href="#lesson-15-16">名词复数</a>、<a href="#lesson-41-42">不可数名词</a></p><p><strong>冠词</strong>：<a href="#lesson-5-6">不定冠词a和an</a>、<a href="#lesson-25-26">定冠词the</a></p><p><strong>代词</strong>：<a href="#lesson-21-22">one</a>、<a href="#lesson-27-28">some和any</a>、<a href="#lesson-115-116">不定代词</a></p><p><strong>动词</strong>：<a href="#lesson-31-32">动词现在分词</a>、<a href="#lesson-49-50">动词三单</a>、<a href="#lesson-71-72">动词过去式和过去分词</a>、<a href="#lesson-87-88">动词不定式</a></p><p><strong>形容词</strong>：<a href="#lesson-73-74">形容词变副词</a>、<a href="#lesson-107-108">比较级和最高级①</a>、<a href="#lesson-111-112">比较级和最高级②</a></p><p><strong>副词</strong>：<a href="#lesson-103-104">too和enough</a>、<a href="#lesson-51-52">表示频率</a></p><p><strong>介词</strong>：<a href="#lesson-23-24">on</a>、<a href="#lesson-25-26">in</a>、<a href="#lesson-77-78">at</a>、<a href="#lesson-33-34">over</a>、<a href="#lesson-53-54">like</a></p><p><strong>情态动词</strong>：<a href="#lesson-29-30">must</a>、<a href="#lesson-43-44">can</a>、<a href="#lesson-131-132">may</a></p><p><strong>have</strong>：<a href="#lesson-59-60">用法①</a>、<a href="#lesson-61-62">用法②</a>、<a href="#lesson-81-82">用法③</a>、<a href="#lesson-87-88">用法④</a></p><p><strong>推测的表达</strong>：<a href="#lesson-127-128">现在的“一定是”与“一定不是”</a>、<a href="#lesson-129-130">过去的“一定是”与“一定不是”</a>、<a href="#lesson-131-132">可能may和might</a></p><p><strong>固定搭配</strong>：<a href="#lesson-79-80">have got</a>、<a href="#lesson-95-96">had better</a>、<a href="#lesson-125-126">have to</a>、<a href="#lesson-85-86">have gone和have been</a></p><p><strong>其他</strong>：<a href="#lesson-79-80">much和many</a>、<a href="#lesson-109-110">little和few</a>、<a href="#lesson-35-36">other和another</a>、<a href="#lesson-63-64">so和because</a>、<a href="#lesson-113-114">not、no、none之间的关系</a>、<a href="#lesson-83-84">&#39;s缩写</a>、<a href="#lesson-57-58">时间的表达</a>、<a href="#lesson-23-24">双宾语</a></p></div><h2 id="lesson-1-2" tabindex="-1">Lesson 1~2 <a class="header-anchor" href="#lesson-1-2" aria-label="Permalink to &quot;Lesson 1~2&quot;">​</a></h2><div class="danger custom-block"><p class="custom-block-title">⚡本课重点</p><p><strong>一般疑问句</strong>：通过主谓倒装可将带有<code>be</code>的陈述句变为一般疑问句，即将<code>be</code>的适当形式移至主语之前</p><p>e.g. <code>He is a teacher.</code> =&gt; <code>Is he a teacher?</code></p><p><strong>be动词</strong>：前期先记住以下三种形式</p><ul><li><code>am</code>，只能跟在第一人称单数<code>I</code>后面</li><li><code>is</code>，跟在第三人称单数<code>he</code>、<code>she</code>、<code>it</code>等后面</li><li><code>are</code>，搭配<code>you</code>使用，不管是单数还是复数</li></ul></div><h2 id="lesson-3-4" tabindex="-1">Lesson 3~4 <a class="header-anchor" href="#lesson-3-4" aria-label="Permalink to &quot;Lesson 3~4&quot;">​</a></h2><div class="danger custom-block"><p class="custom-block-title">⚡本课重点</p><p>含有<code>be</code>动词的简单陈述句</p><p>e.g. <code>This is my umbrella.</code></p><p><strong>否定句</strong>：否定陈述句与肯定陈述句相反，它表示「否定」，并且含有一个如<code>not</code>之类的否定词。</p><p>含有be动词的句子如果变为否定句，就是在be动词的后面加上not</p><p>e.g. <code>This is not my umbrella.</code></p><p>针对一般疑问句的否定简答语是<code>No, it&#39;s not.</code>或<code>No, it isn&#39;t.</code></p><p><strong>祈使句</strong>：用来表达命令、要求、请求或劝告等，它的主语是<code>you(即听的一方)</code>，但通常不显示说明</p><p>结构：<strong><code>动词原形</code>+<code>名词(代词)</code></strong></p><p>e.g. <code>Open the window, please.</code></p><ul><li>以动词原形开头的句子，或在动词原型前面加<code>do</code>(只限于省略第二人称主语的句子)的句子，都是祈使句</li><li>以<code>let</code>开头的句子也是祈使句</li></ul><p><strong>倒装句</strong>：<code>be</code>动词放在<code>here</code>的后面，就可以成为简单的倒装句式</p><p>e.g. <code>Here is my umbrella.</code></p><p><strong>it suits me</strong>：习惯用语，表示「<strong>某物很合适我</strong>」</p></div><h2 id="lesson-5-6" tabindex="-1">Lesson 5~6 <a class="header-anchor" href="#lesson-5-6" aria-label="Permalink to &quot;Lesson 5~6&quot;">​</a></h2><div class="danger custom-block"><p class="custom-block-title">⚡本课重点</p><p><strong>选择疑问句</strong>：<strong>含有<code>or</code>的疑问句称为选择疑问句</strong>。选择疑问句的回答必须要用完整的句子，选择疑问句的语调为前升后降。<code>or</code>连接的两个并列成分可以是状语、宾语、表语、谓语或是两个分句</p><p>e.g. <code>Is she German or Swedish?</code></p><p><strong>不定冠词a和an</strong>：</p><ul><li>a和an具有不确定的意思</li><li>a和an只能用于单数可数名词的前面</li><li>a用于辅音音标的普通名词之前，发音为<code>/ə/</code></li><li>an用于元音音标的单词之前，发音为<code>/ən/</code></li></ul><p>e.g. <code>This is a B/C/D/G/J/K/P/Q/R/T/U/V/W/Y/Z</code>、<code>This is an A/E/F/H/I/L/M/N/O/S/X</code></p><hr><p><strong>称呼的用法</strong>：</p><ul><li>Mr. A(未知)</li><li>Mrs. A(已婚)</li><li>Miss A(未婚)</li><li>Ms.A(未知)</li></ul><p>根据经验，大部分情况下使用<code>Mr.</code>和<code>Miss</code>就行</p><p><code>What make is it?</code>在生活中其实很少这么用，更多是用<code>What brand is this?</code></p></div><h2 id="lesson-7-8" tabindex="-1">Lesson 7~8 <a class="header-anchor" href="#lesson-7-8" aria-label="Permalink to &quot;Lesson 7~8&quot;">​</a></h2><h3 id="特殊疑问句" tabindex="-1">特殊疑问句 <a class="header-anchor" href="#特殊疑问句" aria-label="Permalink to &quot;特殊疑问句&quot;">​</a></h3><div class="danger custom-block"><p class="custom-block-title">⚡本课重点</p><p><strong>特殊疑问句</strong>：以特殊疑问词引导的问句都叫特殊疑问句。与一般疑问句的区别在于特殊疑问句不可以用<code>yes</code>或<code>no</code>回答</p><p>结构为: <strong><code>特殊疑问词</code>+<code>助动词</code>+<code>主语</code>+<code>实义动词</code></strong> 或者是 <strong><code>特殊疑问词</code>+<code>一般疑问句(去掉答案)</code></strong></p><table><thead><tr><th>what</th><th>when</th><th>which</th><th>why</th><th>where</th><th>how</th><th>who</th><th>whom</th><th>whose</th></tr></thead><tbody><tr><td>什么</td><td>何时</td><td>哪一个</td><td>为什么</td><td>哪里</td><td>如何</td><td>谁</td><td>谁(宾格)</td><td>谁的</td></tr></tbody></table><p><strong>too和either</strong>：两者都表示「<strong>也</strong>」的意思，<code>too</code>一般用于肯定句，<code>either</code>用于否定句和疑问句，它们一般都是放在句尾，且前面通常用逗号隔开</p><p><strong>询问国籍</strong>：<strong><code>What nationality are you?</code> 等价于 <code>Where are you from?</code></strong></p></div><h2 id="lesson-9-10" tabindex="-1">Lesson 9~10 <a class="header-anchor" href="#lesson-9-10" aria-label="Permalink to &quot;Lesson 9~10&quot;">​</a></h2><div class="danger custom-block"><p class="custom-block-title">⚡本课重点</p><p><strong>how引导的特殊疑问句</strong></p><p>e.g. <code>She&#39;s very well.</code> =&gt; <code>Is she well today?</code> =&gt; <code>How&#39;s she today?</code></p><p><em>先把陈述句中的<code>be</code>动词提到句首得到一般疑问句，再用<code>how</code>对一般疑问句中的答案<code>well</code>进行提问，并将其提到句首</em></p><hr><p><strong>形容词</strong>：形容词用来修饰名词，表示人或事物的性质、特征。通常可将形容词分为「<strong>性质形容词</strong>」和「<strong>叙述形容词</strong>」，其位置不一定都放在名词的前面。<em>英文的形容词用法和中文语境中的用法是保持一致的</em></p><ul><li>直接说明事物的性质或特征的形容词是「性质形容词」，它有级的变化，可用程度副词进行修饰，在句中可作定语、表语和补语</li><li>「叙述形容词」只能作表语，所以又称为表语形容词。这类形容词没有级的变化，也不能用程度副词进行修饰，大多数以<code>a</code>开头的形容词都属于这一类</li><li>形容词作定语修饰名词时，要放在名词的前面。但是形容词修饰以<code>thing</code>结尾的词语时，可放在这些词的后面</li></ul></div><h2 id="lesson-11-12" tabindex="-1">Lesson 11~12 <a class="header-anchor" href="#lesson-11-12" aria-label="Permalink to &quot;Lesson 11~12&quot;">​</a></h2><div class="danger custom-block"><p class="custom-block-title">⚡本课重点</p><p><strong>whose引导的特殊疑问句</strong></p><p>e.g. <code>This is her dress.</code> =&gt; <code>Is this her dress?</code> =&gt; <code>Whose dress is this?</code></p><p><em>先把陈述句中的<code>be</code>动词提到句首得到一般疑问句，再用<code>whose</code>对一般疑问句中的答案<code>her</code>进行提问，并将其提到句首</em></p><p><strong>名词所有格</strong>：在词尾加<code>&#39;s</code>构成，在句中不仅可以作定语，还可以作表语</p><p>e.g. <code>John&#39;s dog.</code></p></div><h2 id="lesson-13-14" tabindex="-1">Lesson 13~14 <a class="header-anchor" href="#lesson-13-14" aria-label="Permalink to &quot;Lesson 13~14&quot;">​</a></h2><div class="danger custom-block"><p class="custom-block-title">⚡本课重点</p><p><strong>what引导的特殊疑问句</strong></p><p>e.g. <code>Her new dress is green.</code> =&gt; <code>Is her new dress green?</code> =&gt; <code>What colour is her new dress?</code></p><p><em>先把陈述句中的<code>be</code>动词提到句首得到一般疑问句，再用<code>what</code>对一般疑问句中的答案<code>green</code>进行提问，并将其提到句首</em></p><p><strong>is it连读</strong>：<code>it</code>要失去爆破，发音类似<code>/isit/</code></p><p><strong>smart</strong>：通常所表达的意思是「<strong>聪明</strong>」，而不是「漂亮」</p></div><h2 id="lesson-15-16" tabindex="-1">Lesson 15~16 <a class="header-anchor" href="#lesson-15-16" aria-label="Permalink to &quot;Lesson 15~16&quot;">​</a></h2><h3 id="名词复数规则变化" tabindex="-1">名词复数规则变化 <a class="header-anchor" href="#名词复数规则变化" aria-label="Permalink to &quot;名词复数规则变化&quot;">​</a></h3><div class="danger custom-block"><p class="custom-block-title">⚡本课重点</p><p><strong>名词的单/复数</strong>：英语中的可数名词有「<strong>单数</strong>」和「<strong>复数</strong>」两种形式。表示一个人或事物时用单数形式，表示多个人或事物时用复数形式。</p><p><strong>名词的复数规则变化</strong></p><ul><li><p>①一般情况下在词尾直接加<code>-s</code></p><p>e.g. <code>book</code> =&gt; <code>books</code>、<code>pen</code> =&gt; <code>pens</code></p></li><li><p>②以字母<code>s</code>、<code>z</code>、<code>x</code>、<code>ch</code>、<code>sh</code>结尾的单词，在词尾直接加<code>-es</code>，读<code>/iz/</code></p><p>e.g. <code>watch</code> =&gt; <code>watches</code>、<code>fish</code> =&gt; <code>fishes</code>、<code>box</code> =&gt; <code>boxes</code></p></li><li><p>③以辅音字母加<code>y</code>结尾的单词，将<code>y</code>改为<code>i</code>，再加<code>-es</code>，读<code>/z/</code></p><p>e.g. <code>contry</code> =&gt; <code>countries</code>、<code>family</code> =&gt; <code>families</code></p></li><li><p>④以元音字母加<code>y</code>结尾的单词，在词尾直接加<code>-s</code>，读<code>/z/</code></p><p>e.g. <code>day</code> =&gt; <code>days</code>、<code>monkey</code> =&gt; <code>monkeys</code></p></li><li><p>⑤以<code>ce</code>、<code>se</code>、<code>ze</code>、<code>(d)ge</code>结尾的单词，在词尾直接加<code>-s</code>，读<code>/iz/</code></p><p>e.g. <code>bridge</code> =&gt; <code>bridges</code>、<code>blouse</code> =&gt; <code>blouses</code></p></li><li><p>⑥以<code>f</code>、<code>fe</code>结尾的单词，将<code>f</code>或<code>fe</code>改为<code>ves</code>，读<code>/vz/</code></p><p>e.g. <code>knife</code> =&gt; <code>knives</code>、<code>thief</code> =&gt; <code>thieves</code></p></li><li><p>⑦以<code>o</code>结尾的单词一般加<code>-s</code>，部分以辅音字母加<code>o</code>结尾的单词，在词尾直接加<code>-es</code>，读<code>/z/</code></p><p>e.g. <code>zoo</code> =&gt; <code>zoos</code>、<code>tomato</code> =&gt; <code>tomatoes</code></p></li><li><p>⑧以<code>ix</code>结尾的单词，一般将<code>ix</code>改为<code>ices</code></p></li><li><p>⑨以<code>um</code>结尾的单词，将<code>um</code>改为<code>a</code></p></li><li><p>⑩以<code>a</code>结尾的单词，在词尾直接加<code>-e</code></p></li></ul><p>如果句中的主语是名词的复数形式或复数的人称代词时，则句中的<code>be</code>动词要用其复数形式<code>are</code></p><p>e.g. <code>This is a book.</code>、<code>These are my books.</code></p><hr><p><strong>be动词的一般现在时</strong>：英语中的<code>be</code>动词在使用时有人称的变化，在口语中这些变化常用缩略形式</p><table><thead><tr><th>肯定句</th><th>肯定的缩略</th><th>否定的缩略</th></tr></thead><tbody><tr><td>I am</td><td>I&#39;m</td><td>I&#39;m not</td></tr><tr><td>You are</td><td>You&#39;re</td><td>You&#39;re not <code>=</code> You aren&#39;t</td></tr><tr><td>He is</td><td>He&#39;s</td><td>He&#39;s not <code>=</code> He isn&#39;t</td></tr><tr><td>She is</td><td>She&#39;s</td><td>She&#39;s not <code>=</code> She isn&#39;t</td></tr><tr><td>It is</td><td>It&#39;s</td><td>It&#39;s not <code>=</code> It isn&#39;t</td></tr><tr><td>We are</td><td>We&#39;re</td><td>We&#39;re not <code>=</code> We aren&#39;t</td></tr><tr><td>They are</td><td>They&#39;re</td><td>They&#39;re not <code>=</code> They aren&#39;t</td></tr></tbody></table></div><h2 id="lesson-17-18" tabindex="-1">Lesson 17~18 <a class="header-anchor" href="#lesson-17-18" aria-label="Permalink to &quot;Lesson 17~18&quot;">​</a></h2><div class="danger custom-block"><p class="custom-block-title">⚡本课重点</p><p><strong>who引导的特殊疑问句</strong></p><p>e.g. <code>This is young man Jandan.</code> =&gt; <code>Is this young man Jandan?</code> =&gt; <code>Who is this young man?</code></p><p><em>先把陈述句中的<code>be</code>动词提到句首得到一般疑问句，再用<code>who</code>对一般疑问句中的答案<code>Jandan</code>进行提问，并将其提到句首</em></p><p><strong>可数名词复数的发音规则</strong></p><ul><li><p>原词尾发音是清辅音的(除<code>/s/</code>、<code>/∫/</code>、<code>/t∫/</code>)，<code>-s</code>读<code>/s/</code></p><p>e.g. <code>books</code>、<code>cooks</code>、<code>suits</code></p></li><li><p>原词尾发音是元音或浊辅音的(除<code>/z/</code>、<code>/ʒ/</code>、<code>/dʒ/</code>)，如<code>/b/</code>、<code>/d/</code>、<code>/g/</code>等，<code>-s</code>读<code>/z/</code></p><p>e.g. <code>ties</code>、<code>birds</code>、<code>bags</code></p></li><li><p>原词尾发音是<code>/s/</code>、<code>/∫/</code>、<code>/t∫/</code>、<code>/z/</code>、<code>/ʒ/</code>和<code>/dʒ/</code>，<code>-s</code>读<code>/iz/</code></p><p>e.g. <code>dresses</code>、<code>watches</code>、<code>blouses</code></p></li></ul></div><h2 id="lesson-19-20" tabindex="-1">Lesson 19~20 <a class="header-anchor" href="#lesson-19-20" aria-label="Permalink to &quot;Lesson 19~20&quot;">​</a></h2><h3 id="there-be" tabindex="-1">There be <a class="header-anchor" href="#there-be" aria-label="Permalink to &quot;There be&quot;">​</a></h3><div class="danger custom-block"><p class="custom-block-title">⚡本课重点</p><p><strong>There be结构</strong>：此结构可将重要的新信息置于句末，以示强调</p><p>这种句子结构中的<code>there</code>是个引词，本身没有实际意义，常弱读。句子中的<code>be</code>为谓语动词，<code>be</code>后面的名词为实际主语，句子最后部分为地点(时间)状语</p><ul><li><p><strong>肯定句</strong>：<em>表示某处有某物</em>。<strong><code>There am/is/are</code>+<code>名词</code>(+<code>地点(时间)状语</code>)</strong></p><p>e.g. <code>There is a pen.</code></p></li><li><p><strong>否定句</strong>：<em>要在<code>be</code>的后面加上<code>not</code>即可</em>。<strong><code>There am/is/are</code>+<code>not</code>+<code>名词</code>(+<code>地点(时间)状语</code>)</strong></p><p>e.g. <code>There isn&#39;t a pen.</code></p></li><li><p><strong>疑问句</strong>：<em>只需将<code>be</code>提到句首(<code>there</code>前面)即可</em>。<strong><code>Am/Is/Are there</code>+<code>名词</code>(+<code>地点(时间)状语</code>)</strong></p><p>e.g. <code>Is there a pen?</code></p></li><li><p><strong>特殊疑问句</strong>：<em>在一般疑问句的句首加上特殊疑问词并去掉答案</em>。<strong><code>特殊疑问词</code>+<code>am/is/are there</code>(+<code>地点(时间)状语</code>)</strong></p><p>e.g. <code>There is a pen.</code> =&gt; <code>Is there a pen?</code> =&gt; <code>What is there?</code></p><p><em>先把陈述句中的<code>be</code>动词提到句首得到一般疑问句，再用<code>what</code>对一般疑问句中的答案<code>pen</code>进行提问，并将其提到句首</em></p></li></ul></div><h2 id="lesson-21-22" tabindex="-1">Lesson 21~22 <a class="header-anchor" href="#lesson-21-22" aria-label="Permalink to &quot;Lesson 21~22&quot;">​</a></h2><div class="danger custom-block"><p class="custom-block-title">⚡本课重点</p><p><strong>which引导的特殊疑问句</strong>：用来询问事物或性质，需要从限定的、特指的范围中做出选择</p><p>e.g. <code>This is my book.</code> =&gt; <code>Is this your book?</code> =&gt; <code>Which is your book?</code></p><p><em>先把陈述句中的<code>be</code>动词提到句首得到一般疑问句，再用<code>which</code>对一般疑问句中的答案<code>this</code>进行提问，并将其提到句首</em></p><p><strong>不定代词one</strong>：用来代替前文出现过的人称代词或可数名词，以免重复。它有复数形式<code>ones</code>，可以和冠词连用，也可以有自己的定语</p><ul><li><code>one</code>、<code>that</code>和<code>it</code>之间的区别：<code>one</code>表示泛指，<code>that</code>和<code>it</code>表示特指，<code>that</code>与所指的名词为同类，但不是同一个，而<code>it</code>与所指的名词是同一个</li></ul></div><h2 id="lesson-23-24" tabindex="-1">Lesson 23~24 <a class="header-anchor" href="#lesson-23-24" aria-label="Permalink to &quot;Lesson 23~24&quot;">​</a></h2><h3 id="双宾语" tabindex="-1">双宾语 <a class="header-anchor" href="#双宾语" aria-label="Permalink to &quot;双宾语&quot;">​</a></h3><div class="danger custom-block"><p class="custom-block-title">⚡本课重点</p><p><strong>双宾语</strong>：有些动词可以有两个宾语，往往一个指代人，一个指代物。指人的叫「<strong>间接宾语</strong>」，指物的叫「<strong>直接宾语</strong>」</p><ul><li><p>间接宾语一般放在直接宾语的前面，人要用代词的宾格。<strong><code>give sb. sth.</code></strong></p><p>e.g. <code>show me the money</code></p></li><li><p>如果直接宾语是个人称代词时，就需要在间接宾语的前面加上介词<code>to</code>，并把这个带<code>to</code>的间接宾语放在直接宾语的后面。<strong><code>give sth. to sb.</code></strong></p><p>e.g. <code>give it to me</code></p><p><strong><code>give sb. sth.</code> 等价于 <code>give sth. to sb.</code></strong>，两者是同义结构，可以相互转换</p></li><li><p>当直接宾语是名词时，它既可以放在间接宾语的后面，也可以在间接宾语的前面加<code>to</code>，并把这个带<code>to</code>的间接宾语放在直接宾语的后面</p></li></ul><hr><p><strong>where引导的特殊疑问句</strong>：</p><p>e.g. <code>My book is on the shelf.</code> =&gt; <code>Is my book on the shelf?</code> =&gt; <code>Where is my book?</code></p><p><em>先把陈述句中的<code>be</code>动词提到句首得到一般疑问句，再用<code>where</code>对一般疑问句中的答案<code>on the shelf</code>进行提问，并将其提到句首</em></p><hr><p><strong>介词on</strong>：经常用在名词、名词短语、代词或动名词的前面，用来表示人物、事件等之间的各种关系，如空间关系、时间关系、因果关系等。介词始终带有宾语，即使介词与宾语之间分隔开时，这种关系仍然存在</p><p>介词短语：<strong><code>介词</code>+<code>名词</code>(+<code>介词</code>)</strong></p><p>e.g. <code>on time</code>、<code>in the middle of</code></p><p>介词不能在句子中独立充当一个成分，需要和一个名词或与之相当的词构成介词短语来充当句子中的一个成分，和介词构成短语的那个部分称为「<strong>介词的宾语</strong>」</p><p><code>on</code>在不同的搭配情况下有不同的含义</p><ul><li><p>在一个平面或线上</p><p>e.g. <code>on the table</code></p></li><li><p>在某一个不精确的时间</p><p>e.g. <code>on Monday</code></p></li></ul></div><h2 id="lesson-25-26" tabindex="-1">Lesson 25~26 <a class="header-anchor" href="#lesson-25-26" aria-label="Permalink to &quot;Lesson 25~26&quot;">​</a></h2><div class="danger custom-block"><p class="custom-block-title">⚡本课重点</p><p><strong>介词in</strong>：表示「<strong>地点、场所、部位</strong>」等，它的用法很多，本课学习的是其「<strong>在…里面</strong>」的意思</p><ul><li><p>在某范围或空间内</p><p>e.g. <code>There is a refrigerator in the kitchen.</code></p></li><li><p>在某一段时间内</p><p>e.g. <code>in the morning</code></p></li></ul><hr><p><strong>定冠词the</strong>：表示特指，不论是指人、物、单数、复数，其形式都不会发生变化。与指示代词<code>this</code>和<code>that</code>同源，有「<strong>这(那)个</strong>」的意思，但较弱，可以和一个名词连用，来表示某个或某些特定的人或物</p><ul><li>特指双方都明白的人或物</li><li>前文提到过的人或物</li><li>世上独一无二的事物</li><li>与单数名词连用时表示一类事物；与形容词、分词连用时表示一类人</li><li>用在数词、形容词最高级、<code>only</code>、<code>very</code>、<code>same</code>等前面</li><li>与复数名词连用时表示整个群体</li><li>用在身体部位的名词前面时，相当于物主代词，表示「所有」</li><li>用在某些由普通名词构成的国家名称、机关团体、阶级等专用名词前面</li><li>用在表示乐器的名词前面</li><li>用在姓氏的复数名词前面，表示一家人</li><li>用在惯用语中</li></ul><p><code>the</code>在元音前读<code>/ði/</code>，e.g. <code>the engineer</code></p><p><code>the</code>在辅音前读<code>/ðə/</code>，e.g. <code>the floor</code></p></div><h2 id="lesson-27-28" tabindex="-1">Lesson 27~28 <a class="header-anchor" href="#lesson-27-28" aria-label="Permalink to &quot;Lesson 27~28&quot;">​</a></h2><div class="danger custom-block"><p class="custom-block-title">⚡本课重点</p><p><strong>how many引导的特殊疑问句</strong>：用来询问数量</p><p>e.g. <code>There are two books on the desk.</code> =&gt; <code>Are there two books on the desk?</code> =&gt; <code>How many books are there on the desk?</code></p><p><em>先把陈述句中的<code>be</code>动词提到句首得到一般疑问句，再用<code>how many</code>对一般疑问句中的答案<code>two books</code>进行提问，并将其提到句首</em></p><hr><p><strong>some和any的区别</strong>：在英语中，<code>some</code>和<code>any</code>是两个最常用的数量词，它们都表示「<strong>一些</strong>」。再具体一点话<code>some</code>表示「<strong>某些</strong>」，<code>any</code>表示「<strong>任一</strong>」</p><ul><li><code>some</code>：修饰可数名词复数和不可数名词，表示「某些」但不是「全部」，通常用于肯定句。在疑问句中，所希望的回答是<code>yes</code>时也可以用<code>some</code></li><li><code>any</code>：表示「任一」，即不确定的数量，通常用于否定句和疑问句</li></ul></div><h2 id="lesson-29-30" tabindex="-1">Lesson 29~30 <a class="header-anchor" href="#lesson-29-30" aria-label="Permalink to &quot;Lesson 29~30&quot;">​</a></h2><h3 id="情态动词must" tabindex="-1">情态动词must <a class="header-anchor" href="#情态动词must" aria-label="Permalink to &quot;情态动词must&quot;">​</a></h3><div class="danger custom-block"><p class="custom-block-title">⚡本课重点</p><p><strong>情态动词</strong>：是一种本身没有词义，表示说话人的语气和情态的助动词。</p><ul><li>它不能单独做谓语，只能和后面的动词原形一起构成谓语动词</li><li>它没有人称和数的变化</li><li>含有情态动词的句子，否定句和疑问句都是在情态动词上发生变化</li></ul><hr><p><strong>情态动词must</strong>：单词本义为「<strong>必须</strong>」。它必须与其他东西连用，没有时态、人称和数的变化</p><ul><li><p><strong>肯定句</strong>：<em>表示必须做某事</em>。<strong><code>主语</code>+<code>must</code>+<code>V.</code>(+<code>其他</code>)</strong></p><p>e.g. <code>I must drink some water.</code></p></li><li><p><strong>否定句</strong>：<em>只需在<code>must</code>的后面加上<code>not</code>即可。其否定形式表示「<strong>禁止</strong>」而不是简单的<strong>非必须</strong>，语气强烈，不要随便使用</em>。<strong><code>主语</code>+<code>must not</code>+<code>V.</code>(+<code>其他</code>)</strong></p><p>e.g. <code>You mustn&#39;t smoke here.</code></p></li><li><p><strong>一般疑问句</strong>：<em>只需将<code>must</code>提到句首(主语前面)即可</em>。<strong><code>Must</code>+<code>主语</code>+<code>V.</code>(+<code>其他</code>)</strong></p><p>e.g. <code>Must I do the homework today?</code></p></li><li><p><strong>特殊疑问句</strong>：<em>在一般疑问句的句首加上特殊疑问词并去掉答案</em>。<strong><code>特殊疑问词</code>+<code>must</code>+<code>主语</code>+<code>V.</code>(+<code>其他</code>)</strong></p><p>e.g. <code>I must drink some water.</code> =&gt; <code>Must I drink some water?</code> =&gt; <code>What must I do?</code></p><p><em>先把陈述句中的<code>must</code>提到句首得到一般疑问句，再用<code>what</code>对一般疑问句中的答案<code>drink some water</code>进行提问，并将其提到句首</em></p></li></ul></div><h2 id="lesson-31-32" tabindex="-1">Lesson 31~32 <a class="header-anchor" href="#lesson-31-32" aria-label="Permalink to &quot;Lesson 31~32&quot;">​</a></h2><h3 id="现在进行时" tabindex="-1">现在进行时 <a class="header-anchor" href="#现在进行时" aria-label="Permalink to &quot;现在进行时&quot;">​</a></h3><div class="danger custom-block"><p class="custom-block-title">⚡本课重点</p><p><strong>时</strong>：动作发生的时间</p><p><strong>态</strong>：动作的样子和状态</p><p><strong>现在进行时</strong>：动作发生的时间是「<strong>现在</strong>」，动作的状态是「<strong>进行中</strong>」。核心结构是 <strong><code>am/is/are</code>+<code>V.ing</code></strong>，其中助动词<code>be</code>表示动作发生的时间，实义动词<code>V.ing</code>表示动作的状态</p><ul><li><p><strong>肯定句</strong>：<em>表示现在正在进行或者发生的动作、状态</em>。<strong><code>主语</code>+<code>am/is/are</code>+<code>V.ing</code>(+<code>其他</code>)</strong></p><p>e.g. <code>He&#39;s reading a book.</code></p></li><li><p><strong>否定句</strong>：<em>只需在<code>be</code>的后面加上<code>not</code>即可</em>。<strong><code>主语</code>+<code>am/is/are</code>+<code>not</code>+<code>V.ing</code>(+<code>其他</code>)</strong></p><p>e.g. <code>He&#39;s not reading a book.</code></p></li><li><p><strong>一般疑问句</strong>：<em>只需将<code>be</code>提到句首(主语前面)即可</em>。<strong><code>Am/Is/Are</code>+<code>主语</code>+<code>V.ing</code>(+<code>其他</code>)</strong></p><p>e.g. <code>Is he reading a book?</code></p></li><li><p><strong>特殊疑问句</strong>：<em>在一般疑问句的句首加上特殊疑问词并去掉答案</em>。<strong><code>特殊疑问词</code>+<code>am/is/are</code>+<code>主语</code>+<code>V.ing</code>(+<code>其他</code>)</strong></p><p>e.g. <code>He&#39;s reading a book.</code> =&gt; <code>Is he reading a book?</code> =&gt; <code>What is he doing?</code></p><p><em>先把陈述句中的<code>be</code>动词提到句首得到一般疑问句，再用<code>what</code>对一般疑问句中的答案<code>reading a book</code>进行提问，并将其提到句首</em></p></li></ul><hr><p><strong>动词现在分词的规则变化</strong></p><ul><li><p>对于大多数动词来说，在动词后面直接加<code>-ing</code>即可构成现在分词</p><p>e.g. <code>doing</code>、<code>climbing</code>；</p></li><li><p>以<code>-e</code>结尾的动词，要去掉<code>-e</code>再加<code>-ing</code></p><p>e.g. <code>making</code>、<code>coming</code></p></li><li><p>如果动词只有一个元音字母，并且其后面跟了一个辅音字母时(<em>往往以重读闭音节的形式出现，即<code>辅元辅</code></em>)，先双写词尾辅音字母再加<code>-ing</code></p><p>e.g. <code>running</code>、<code>sitting</code></p></li></ul><hr><p><strong>现在进行时还能表示将来</strong>：某些非延续性动词的现在进行时可表示按计划、安排将要发生的动作，常见的有<code>go</code>、<code>come</code>、<code>arrive</code>、<code>leave</code>、<code>start</code>等</p><p>e.g. <code>They&#39;re getting married next month.</code>、<code>They&#39;re leaving for Beijing.</code></p><hr><p><strong>特殊疑问句的特殊情况</strong>：对主语提问时，直接用特殊疑问词替代主语即可</p><p>e.g. <code>Tim is climbing the tree.</code> =&gt; <code>Who climbing the tree?</code></p><p><em>这个例子中，直接对主语<code>Tim</code>进行提问，用<code>Who</code>将其替代即可</em></p></div><h2 id="lesson-33-34" tabindex="-1">Lesson 33~34 <a class="header-anchor" href="#lesson-33-34" aria-label="Permalink to &quot;Lesson 33~34&quot;">​</a></h2><div class="danger custom-block"><p class="custom-block-title">⚡本课重点</p><p>在<a href="#lesson-31-32">31~32课</a>中学习了现在进行时的<code>be</code>单数形式，本节来学习其复数形式</p><p>当句中主语名词为复数、人称代词为第二人称或第三人称复数时，助动词<code>be</code>的现在时形式应为<code>are</code></p><p>e.g. <code>They are walking over the bridge.</code></p><p><strong>on和over的区别</strong>：它们都有「<strong>在...上面</strong>」的意思。但是<code>on</code>的关系双方之间需要直接接触表面，而<code>over</code>的关系双方可以不直接接触表面，常常用于表示悬浮在其上面</p><p>e.g. <code>There is a book on the desk.</code>、<code>The sky is over our heads.</code></p><p><strong>ship和boat的区别</strong>：它们都是「船」的意思。但是<code>ship</code>表示的是在海洋中行驶的「<strong>大船</strong>」，而<code>boat</code>则是在河流中行驶的「<strong>小船</strong>」</p></div><h2 id="lesson-35-36" tabindex="-1">Lesson 35~36 <a class="header-anchor" href="#lesson-35-36" aria-label="Permalink to &quot;Lesson 35~36&quot;">​</a></h2><div class="danger custom-block"><p class="custom-block-title">⚡本课重点</p><p><strong>动词短语</strong>：通常是指在动词的后面跟一个介词或副词短语形成的结构</p><p>结构：<strong><code>动词</code>+<code>介词/副词小品词</code></strong></p><p>在英语中存在着一种用动词短语代替与其同义的单个动词的用法，这种用法称为「<strong>动词短语化</strong>」。例如听到敲门声，我们会说<code>come in</code>，而不会用<code>enter</code>来表达。最常见的动词短语是由英语中最短小和最简单的动词构成的，这些动词常与表示位置或方向的词组合，例如<code>along</code>、<code>down</code>、<code>in</code>、<code>out</code>、<code>off</code>、<code>on</code>、<code>over</code>、<code>under</code>等</p><p>不仅一个动词可以和大量的介词或副词小品词组合在一起构成动词短语，一个动词短语本身也可能有几种不同的意思</p><p>e.g. <code>put on your coat</code>、<code>put it on</code></p><hr><p><strong>other和another</strong></p><ul><li><code>other</code>+<code>单数/复数</code></li><li><code>another</code>+<code>单数</code></li></ul></div><h2 id="lesson-37-38" tabindex="-1">Lesson 37~38 <a class="header-anchor" href="#lesson-37-38" aria-label="Permalink to &quot;Lesson 37~38&quot;">​</a></h2><h3 id="一般将来时" tabindex="-1">一般将来时 <a class="header-anchor" href="#一般将来时" aria-label="Permalink to &quot;一般将来时&quot;">​</a></h3><div class="danger custom-block"><p class="custom-block-title">⚡本课重点</p><p><strong>一般将来时</strong>：动作发生的时间是「<strong>将来</strong>」，动作没有具体的状态(<strong>零状态</strong>)</p><p>本节课要学习的是 <strong><code>be</code>+<code>going to</code>+<code>V.</code></strong> 结构的一般将来时。在之后的<a href="#lesson-91-92">91~92课</a>中会学习 <strong><code>will/shall</code>+<code>V.</code></strong> 结构的一般将来时</p><p>当句中主语名词为复数、人称代词为第二人称或第三人称复数时，助动词<code>be</code>的现在时形式应为<code>are</code>。在口语中常常会用<code>gonna</code>替代<code>going to</code></p><p><strong>be going to表示将来</strong></p><ul><li><p><strong>肯定句</strong>：<strong><code>主语</code>+<code>am/is/are</code>+<code>going to</code>+<code>V.</code>(+<code>其他</code>)</strong></p><ul><li><p><em>表示打算、准备做某事</em></p><p>e.g. <code>He is going to sleep.</code></p></li><li><p><em>表示按计划、安排要发生的事</em></p><p>e.g. <code>The meeting is going to begin at nine.</code></p></li><li><p><em>表示预言一件事即将发生</em></p><p>e.g. <code>It&#39;s going to rain.</code></p></li></ul></li><li><p><strong>否定句</strong>：<em>只需在<code>be</code>的后面加上<code>not</code>即可</em>。<strong><code>主语</code>+<code>am/is/are</code>+<code>not</code>+<code>going to</code>+<code>V.</code>(+<code>其他</code>)</strong></p><p>e.g. <code>He is not going to sleep.</code></p></li><li><p><strong>一般疑问句</strong>：<em>只需将<code>be</code>提到句首(主语前面)即可</em>。<strong><code>Am/Is/Are</code>+<code>主语</code>+<code>going to</code>+<code>V.</code>(+<code>其他</code>)</strong></p><p>e.g. <code>Is he going to sleep?</code></p></li><li><p><strong>特殊疑问句</strong>：<em>在一般疑问句的句首加上特殊疑问词并去掉答案</em>。<strong><code>特殊疑问词</code>+<code>am/is/are</code>+<code>主语</code>+<code>going to</code>+<code>V.</code>(+<code>其他</code>)</strong></p><p>e.g. <code>He is going to sleep.</code> =&gt; <code>Is he going to sleep?</code> =&gt; <code>What is he going to do?</code></p><p><em>先把陈述句中的<code>be</code>动词提到句首得到一般疑问句，再用<code>what</code>对一般疑问句中的答案<code>sleep</code>进行提问，并将其提到句首</em></p></li></ul><hr><p><strong>宾语补足语</strong>：对宾语进行补充说明，<strong><code>动词</code>+<code>代词(名词)</code>+<code>形容词</code></strong></p><p>e.g. <code>paint the bookcase pink.</code></p><p><strong>及物动词</strong>：本身词义不完整，后面必须跟宾语</p><p><strong>不及物动词</strong>：本身词义完整，后面不需要跟宾语。如果要跟宾语，则动词后面要加介词之后才可以跟宾语</p><p><strong>paint it连读</strong>：发音类似<code>/peintit/</code>，<code>it</code>要失去爆破</p></div><h2 id="lesson-39-40" tabindex="-1">Lesson 39~40 <a class="header-anchor" href="#lesson-39-40" aria-label="Permalink to &quot;Lesson 39~40&quot;">​</a></h2><div class="danger custom-block"><p class="custom-block-title">⚡本课重点</p><p><strong>祈使句否定形式</strong>：在动词原形前面加上<code>Don&#39;t</code>或<code>Do not</code>即可，结构为 <strong><code>Don&#39;t(Do not)</code>+<code>V.</code>+<code>名词(代词)</code></strong>。相关概念和肯定句式参考之前的<a href="#lesson-3-4">3~4课</a></p><p>e.g. <code>Don&#39;t do it</code></p><hr><p><strong>双宾语</strong>：相关概念参考之前的<a href="#lesson-23-24">23~24课</a>，本节课主要讲的是其<code>give sth. to sb.</code>的形式</p><p><strong><code>动词</code>+<code>介词</code>的词组</strong>，如果再加名词的话，可以放中间也可以放后面。而如果是代词的话，只能放中间</p><p><strong>give it连读</strong>：发音类似<code>/givit/</code>，<code>it</code>要失去爆破</p><p><strong>put it连读</strong>：发音类似<code>/pʊtit/</code>，<code>it</code>要失去爆破</p><p><strong>drop it连读</strong>：发音类似<code>/drɒpit/</code>，<code>it</code>要失去爆破</p><p><strong>front of连读</strong>：发音类似<code>/frʌntof/</code>，<code>of</code>夺取<code>front</code>中的<code>t</code>发音，<code>it</code>要失去爆破</p></div><h2 id="lesson-41-42" tabindex="-1">Lesson 41~42 <a class="header-anchor" href="#lesson-41-42" aria-label="Permalink to &quot;Lesson 41~42&quot;">​</a></h2><div class="danger custom-block"><p class="custom-block-title">⚡本课重点</p><p><strong>不可数名词</strong>：不可数名词的前面不能加<code>a</code>或<code>an</code>，也没有复数形式，也就是说前面不能加常规的数量词。如果想表示「一些」，可以用<code>some</code>或<code>any</code>等特定的词</p><ul><li><p>如果想表示量的概念时，要用某种「<strong>容器</strong>」承载不可数名词，然后就可以对其使用常规数量词来描述了</p><p>e.g. <code>two bottles of milk</code></p></li></ul><hr><p><strong>There be结构中使用可数名词和不可数名词</strong>：当<code>There be</code>后面跟单数名词或不可数名词时，<code>be</code>要用<code>is</code>；而当后面跟复数名词时，<code>be</code>要用<code>are</code>。<code>There be</code>后面的名词是句子的主语</p><ul><li><p><strong><code>There is</code>+<code>名词单数/不可数名词</code>(+<code>地点(时间)状语</code>)</strong></p><p>e.g. <code>There&#39;s some milk.</code></p></li><li><p><strong><code>There are</code>+<code>可数名词复数</code>(+<code>地点(时间)状语</code>)</strong></p><p>e.g. <code>There&#39;re two books on the desk.</code></p></li><li><p>如果后面跟多个并列的名词时，<code>be</code>的形式以第一个名词为准</p><p>e.g. <code>There&#39;s a pen, two books and a knife on the desk.</code></p></li></ul></div><h2 id="lesson-43-44" tabindex="-1">Lesson 43~44 <a class="header-anchor" href="#lesson-43-44" aria-label="Permalink to &quot;Lesson 43~44&quot;">​</a></h2><h3 id="情态动词can" tabindex="-1">情态动词can <a class="header-anchor" href="#情态动词can" aria-label="Permalink to &quot;情态动词can&quot;">​</a></h3><div class="danger custom-block"><p class="custom-block-title">⚡本课重点</p><p><strong>情态动词can</strong>：单词本义为「<strong>能</strong>」。它本身不表示动作，只表示体力和脑力方面的能力或客观可能，它必须与其他东西连用，没有人称和数的变化</p><ul><li><p><strong>肯定句</strong>：<em>表示能力或可能</em>。<strong><code>主语</code>+<code>can</code>+<code>V.</code>(+<code>其他</code>)</strong></p><p>e.g. <code>The bird can fly in the sky.</code></p></li><li><p><strong>否定句</strong>：<em>只需在<code>can</code>的后面加上<code>not</code>即可</em>。<strong><code>主语</code>+<code>can</code>+<code>not</code>+<code>V.</code>(+<code>其他</code>)</strong></p><p>e.g. <code>The dog can not fly in the sky.</code></p></li><li><p><strong>一般疑问句</strong>：<em>只需将<code>can</code>提到句首(主语前面)即可</em>。<strong><code>Can</code>+<code>主语</code>+<code>V.</code>(+<code>其他</code>)</strong></p><p>e.g. <code>Can the bird fly in the sky?</code></p></li><li><p><strong>特殊疑问句</strong>：<em>在一般疑问句的句首加上特殊疑问词并去掉答案</em>。<strong><code>特殊疑问词</code>+<code>can</code>+<code>主语</code>+<code>V.</code>(+<code>其他</code>)</strong></p><p>e.g. <code>The bird can fly in the sky.</code> =&gt; <code>Can the bird fly in the sky?</code> =&gt; <code>What can the bird do?</code></p><p><em>先把陈述句中的<code>can</code>提到句首得到一般疑问句，再用<code>what</code>对一般疑问句中的答案<code>fly in the sky</code>进行提问，并将其提到句首</em></p></li></ul><hr><p><strong>find it连读</strong>：发音类似<code>/faɪndit/</code>，<code>it</code>要失去爆破</p></div><h2 id="lesson-45-46" tabindex="-1">Lesson 45~46 <a class="header-anchor" href="#lesson-45-46" aria-label="Permalink to &quot;Lesson 45~46&quot;">​</a></h2><div class="danger custom-block"><p class="custom-block-title">⚡本课重点</p><p><strong>can的否定特殊疑问句</strong>：在<code>can</code>的后面加上<code>not</code>即可，结构为 <strong><code>特殊疑问词</code>+<code>can&#39;t</code>+<code>主语</code>+<code>V.</code>(+<code>其他</code>)</strong></p><p>e.g. <code>Can Pamela read the letter?</code> =&gt; <code>Why can&#39;t Pamela read the letter?</code></p><hr><p><strong>read it连读</strong>：发音类似<code>/redit/</code>，<code>it</code>要失去爆破</p><p><strong>ask sb. to do sth.</strong>：请求某人做某事</p></div><h2 id="lesson-47-48" tabindex="-1">Lesson 47~48 <a class="header-anchor" href="#lesson-47-48" aria-label="Permalink to &quot;Lesson 47~48&quot;">​</a></h2><h3 id="一般现在时" tabindex="-1">一般现在时 <a class="header-anchor" href="#一般现在时" aria-label="Permalink to &quot;一般现在时&quot;">​</a></h3><div class="danger custom-block"><p class="custom-block-title">⚡本课重点</p><p><strong>一般现在时</strong>：动作发生的时间可以是「<strong>过去、现在、将来</strong>」，动作没有具体的状态(<strong>零状态</strong>)</p><p>在本节课之前见过的各种 <strong><code>主语</code>+<code>am/is/are</code>+<code>名词/形容词</code></strong> 句式其实就是「<strong>主系表结构</strong>」的一般现在时，这种句式的谓语是助动词<code>be</code></p><ul><li><p>表示客观事实或存在状态</p><p>e.g. <code>It&#39;s very hot today.</code></p></li></ul><p>而本节课则主要学习其「<strong>主谓宾结构</strong>」的一般现在时<strong>非三单形式</strong>，核心结构是 <strong><code>主语</code>+<code>V.</code></strong>，它的谓语是<code>实义动词</code>。而其三单形式可以看之后的<a href="#lesson-49-50">49~50课</a></p><p><strong>一般现在时非三单形式</strong></p><ul><li><p><strong>肯定句</strong>：<em>实义动词的前面其实有个隐式的<code>do</code>，只是肯定句中经常省略而已</em>。<strong><code>主语</code>(+<code>do</code>)+<code>V.</code>(+<code>其他</code>)</strong></p><p>e.g. <code>I want this job.</code>、<code>I do like tea.</code></p></li><li><p><strong>否定句</strong>：<em>显式使用<code>do</code>并在后面加上<code>not</code>即可</em>。<strong><code>主语</code>+<code>do not</code>+<code>V.</code>(+<code>其他</code>)</strong></p><p>e.g. <code>I do not want this job.</code>、<code>I don&#39;t like tea.</code></p></li><li><p><strong>一般疑问句</strong>：<em>显式使用<code>do</code>并将其提到句首(主语前面)即可</em>。<strong><code>Do</code>+<code>主语</code>+<code>V.</code>(+<code>其他</code>)</strong></p><p>e.g. <code>Do you want this job?</code></p></li><li><p><strong>特殊疑问句</strong>：<em>在一般疑问句的句首加上特殊疑问词并去掉答案</em>。<strong><code>特殊疑问词</code>+<code>do</code>+<code>主语</code>+<code>V.</code>(+<code>其他</code>)</strong></p><p>e.g. <code>I want this job.</code> =&gt; <code>Do you want this job?</code> =&gt; <code>What do you want?</code></p><p><em>先把陈述句中的<code>do</code>提到句首得到一般疑问句，再用<code>what</code>对一般疑问句中的答案<code>this job</code>进行提问，并将其提到句首</em></p></li></ul><hr><p><strong>一般现在时还有如下两种常见用法</strong></p><ul><li>表示习惯或反复的动作</li></ul><p>e.g. <code>She gets up at 7 o&#39;clock every day.</code></p><ul><li>表示将来。主要用于时间、条件让步状语从句中，或表示按时间表、安排等到某时间就发生的事情或动作</li></ul><p>e.g. <code>The train leaves London at six and arrives in Birmingham at eight.</code></p><hr><p><strong>love him连读</strong>：发音类似<code>/lʌvɪm/</code>，<code>him</code>出现发音击穿现象(语音变音)，<code>h</code>不发音</p></div><h2 id="lesson-49-50" tabindex="-1">Lesson 49~50 <a class="header-anchor" href="#lesson-49-50" aria-label="Permalink to &quot;Lesson 49~50&quot;">​</a></h2><h3 id="动词三单变化" tabindex="-1">动词三单变化 <a class="header-anchor" href="#动词三单变化" aria-label="Permalink to &quot;动词三单变化&quot;">​</a></h3><div class="danger custom-block"><p class="custom-block-title">⚡本课重点</p><p>在<a href="#lesson-47-48">47~48课</a>中学习的主要是「<strong>主谓宾结构</strong>」的一般现在时非三单形式，而本节课则主要学习其<strong>三单形式</strong></p><p><strong>一般现在时三单形式</strong></p><p><code>do</code>的第三人称单数为<code>does</code></p><ul><li><p><strong>肯定句</strong>：<em>当<code>does</code>隐藏时，实义动词要用第三人称单数形式；显式使用<code>does</code>的时候，实义动词要用原形</em>。<strong><code>主语</code>(+<code>does</code>)+<code>V.s/es</code>(+<code>其他</code>)</strong></p><p>e.g. <code>He wants this job.</code>、<code>She does like tea.</code></p></li><li><p><strong>否定句</strong>：<em>显式使用<code>does</code>并在后面加上<code>not</code>即可</em>。<strong><code>主语</code>+<code>does not</code>+<code>V.</code>(+<code>其他</code>)</strong></p><p>e.g. <code>He does not want this job.</code>、<code>She doesn&#39;t like tea.</code></p></li><li><p><strong>一般疑问句</strong>：<em>显式使用<code>does</code>并将其提到句首(主语前面)即可</em>。<strong><code>Does</code>+<code>主语</code>+<code>V.</code>(+<code>其他</code>)</strong></p><p>e.g. <code>Does he want this job?</code></p></li><li><p><strong>特殊疑问句</strong>：<em>在一般疑问句的句首加上特殊疑问词并去掉答案</em>。<strong><code>特殊疑问词</code>+<code>does</code>+<code>主语</code>+<code>V.</code>(+<code>其他</code>)</strong></p><p>e.g. <code>He wants this job.</code> =&gt; <code>Does he want this job?</code> =&gt; <code>What does he want?</code></p><p><em>先把陈述句中的<code>does</code>提到句首得到一般疑问句，再用<code>what</code>对一般疑问句中的答案<code>this job</code>进行提问，并将其提到句首</em></p></li></ul><hr><p><strong>动词第三人称单数的变化</strong>：一般现在时中，当主语是第三人称单数时，实义动词要用第三人称单数形式</p><ul><li><p>①一般情况下在词尾直接加<code>s</code></p><p>e.g. <code>want</code> =&gt; <code>wants</code></p></li><li><p>②以辅音字母加<code>y</code>结尾的动词，将<code>y</code>改为<code>i</code>，再加<code>-es</code>，读<code>/z/</code></p><p>e.g. <code>fly</code> =&gt; <code>flies</code>、<code>cry</code> =&gt; <code>cries</code></p></li><li><p>③以元音字母加<code>y</code>结尾的动词，在词尾直接加<code>-s</code>，读<code>/z/</code></p><p>e.g. <code>play</code> =&gt; <code>plays</code></p></li><li><p>④以字母<code>s</code>、<code>x</code>、<code>o</code>、<code>z</code>、<code>ch</code>、<code>sh</code>结尾的动词，这词尾直接加<code>-es</code>，读<code>/iz/</code></p><p>e.g. <code>go</code> =&gt; <code>goes</code>、<code>watch</code> =&gt; <code>watches</code></p></li><li><p>⑤不规则变化</p><p>e.g. <code>have</code> =&gt; <code>has</code></p></li></ul></div><h2 id="lesson-51-52" tabindex="-1">Lesson 51~52 <a class="header-anchor" href="#lesson-51-52" aria-label="Permalink to &quot;Lesson 51~52&quot;">​</a></h2><div class="danger custom-block"><p class="custom-block-title">⚡本课重点</p><p><strong>what...like</strong>：用来询问事物的状况，或询问人物、事物的外观、特征</p><p>e.g. <code>What&#39;s the weather like today?</code>、<code>What&#39;s your house like?</code></p><p><strong>how often</strong>：常用于对某事、动作发生的频率进行提问</p><p>e.g. <code>How often do you go to the cinema?</code></p><hr><p><strong>频率副词</strong>：<code>always</code> &gt; <code>often</code> &gt; <code>usually</code> &gt; <code>sometimes</code> &gt; <code>never</code></p><ul><li>在句子中用于<code>be</code>动词之后</li><li>用在实义动词之前</li><li>如果是否定句或疑问句，用在助动词和实义动词之间</li><li>为表示强调，频率副词可以放在句首或句尾</li></ul></div><h2 id="lesson-53-54" tabindex="-1">Lesson 53~54 <a class="header-anchor" href="#lesson-53-54" aria-label="Permalink to &quot;Lesson 53~54&quot;">​</a></h2><div class="danger custom-block"><p class="custom-block-title">⚡本课重点</p><p><strong>like的不同词性</strong></p><ul><li><p>当其做动词时表示「<strong>喜欢、想要</strong>」</p><p>e.g. <code>I like that sweet girl.</code></p></li><li><p>当其做介词时表示「<strong>怎么样、像...一样</strong>」</p><p>e.g. <code>His car is like mine.</code></p></li><li><p>当其做形容词时表示「<strong>类似的、相似的</strong>」</p></li></ul></div><h2 id="lesson-55-56" tabindex="-1">Lesson 55~56 <a class="header-anchor" href="#lesson-55-56" aria-label="Permalink to &quot;Lesson 55~56&quot;">​</a></h2><div class="danger custom-block"><p class="custom-block-title">⚡本课重点</p><p>本节课主要还是围绕着<strong>一般现在时</strong>进行展开，只是着重使用一般现在时来表示某种习惯的、反复的动作</p><p>e.g. <code>In the morning, Mr. Sawyer goes to work and the children go to school.</code></p><p><strong>take sb. to somewhere</strong>：带某人去某处</p><p>e.g. <code>Their father takes them to school every day.</code></p></div><h2 id="lesson-57-58" tabindex="-1">Lesson 57~58 <a class="header-anchor" href="#lesson-57-58" aria-label="Permalink to &quot;Lesson 57~58&quot;">​</a></h2><h3 id="时间的表达方式" tabindex="-1">时间的表达方式 <a class="header-anchor" href="#时间的表达方式" aria-label="Permalink to &quot;时间的表达方式&quot;">​</a></h3><div class="danger custom-block"><p class="custom-block-title">⚡本课重点</p><p><strong>时间的表达方式</strong></p><ul><li><p>通用表达</p><p>e.g. <code>six o&#39;clock</code> =&gt; 6点整、<code>ten ten</code> =&gt; 10点10分、<code>twelve forty</code> =&gt; 12点40分</p></li><li><p><strong>分 past 时</strong>：表示「<strong>某个整点时间过去了多少分钟</strong>」，这种方式要求当前的自然分钟数必须<code>小于等于30</code></p><p>e.g. <code>half past six</code> =&gt; 6点半、<code>a quarter past ten</code> =&gt; 10点15分、<code>five past twelve</code> =&gt; 12点5分</p></li><li><p><strong>分 to 时</strong>：表示「<strong>距离某个整点时间还差多少分钟</strong>」，这种方式要求当前的自然分钟数必须<code>大于30</code></p><p>e.g. <code>ten to seven</code> =&gt; 6点50分、<code>a quarter to eleven</code> =&gt; 10点45分</p><p><em>在口语环境中，当谈话双方对当前的时间都有个大致的掌握时，可以省略掉介词<code>to</code>。例如：差15分钟就1点 =&gt; <code>quarter one</code></em></p></li></ul><hr><p><strong>一般现在时与现在进行时</strong></p><ul><li><p>一般现在时表达「习惯或反复的动作」时，通常与时间频率副词连用</p><p>e.g. <code>always</code>、<code>often</code>、<code>usually</code>、<code>sometimes</code>、<code>never</code></p></li><li><p>现在进行时表达「此刻正在进行的事情或动作」时，通常与时间状语连用</p><p>e.g. <code>now</code>、<code>at the moment</code>、<code>today</code>、<code>this morning</code>、<code>tonight</code>等</p></li></ul></div><h2 id="lesson-59-60" tabindex="-1">Lesson 59~60 <a class="header-anchor" href="#lesson-59-60" aria-label="Permalink to &quot;Lesson 59~60&quot;">​</a></h2><h3 id="have用法1" tabindex="-1">have用法① <a class="header-anchor" href="#have用法1" aria-label="Permalink to &quot;have用法①&quot;">​</a></h3><div class="danger custom-block"><p class="custom-block-title">⚡本课重点</p><p><strong>have用法①</strong>：单词本义为「<strong>有、拥有</strong>」。它作为动词时有第三人称单数形式<code>has</code>，当它表示「有」这个概念时，其否定形式和疑问形式各有两种。</p><ul><li><p><strong>否定句</strong>：<em>可以在<code>have/has</code>后面直接加<code>not</code>，也可以用助动词<code>do/does</code>的否定形式</em>。<code>have not</code>=<code>haven&#39;t</code>，<code>has not</code>=<code>hasn&#39;t</code></p><ul><li>e.g. <code>I have a car.</code> =&gt; <code>I haven&#39;t a car.</code> =&gt; <code>I don&#39;t have a car.</code></li><li>e.g. <code>He has a car.</code> =&gt; <code>He hasn&#39;t a car.</code> =&gt; <code>He doesn&#39;t have a car.</code></li></ul></li><li><p><strong>一般疑问句</strong>：<em>将<code>have/has</code>提到句首(主语前面)，或者用助动词<code>do/does</code></em></p><ul><li>e.g. <code>Have you a car?</code> =&gt; <code>Do you have a car?</code></li><li>e.g. <code>Has he a car?</code> =&gt; <code>Does he have a car?</code></li></ul></li></ul><p><code>have</code>的另外三种用法参考<a href="#lesson-61-62">61~62课</a>、<a href="#lesson-81-82">81~82课</a>和<a href="#lesson-87-88">87~88课</a></p><hr><p><strong>else</strong>：常常跟在疑问代词、不定代词、疑问副词的后面</p><p>e.g. <code>What else do you want?</code>、<code>Who else is from Japan?</code></p></div><h2 id="lesson-61-62" tabindex="-1">Lesson 61~62 <a class="header-anchor" href="#lesson-61-62" aria-label="Permalink to &quot;Lesson 61~62&quot;">​</a></h2><h3 id="have用法2" tabindex="-1">have用法② <a class="header-anchor" href="#have用法2" aria-label="Permalink to &quot;have用法②&quot;">​</a></h3><div class="danger custom-block"><p class="custom-block-title">⚡本课重点</p><p><strong>have用法②</strong>：常常与表示疼痛和疾病的名词连用。不定冠词<code>a/an</code>与这类名词连用时，分以下几种情况</p><ul><li><p>必须用不定冠词的情况：<code>a cold</code>、<code>a headache</code>、<code>a sore throat</code></p><p>e.g. <code>I have a cold.</code>、<code>I have a headache.</code></p></li><li><p>不定冠词用或不用都行：<code>catch (a) cold</code>、<code>have (a) backache/toothache/stomach ache</code></p><p>e.g. <code>I&#39;ve had (a) toothache all night.</code></p></li><li><p>复数形式的疾病名称前面不用冠词：<code>measles</code>、<code>mumps</code>、<code>shingles</code></p><p>e.g. <code>Most children are in bed with mumps.</code></p></li><li><p>被认为不可数的疾病名词前面不用冠词：<code>flu</code>、<code>gout</code>、<code>hepatitis</code>等</p><p>e.g. <code>I was in bed with flu for ten days.</code></p></li><li><p><code>the</code>也可以跟<code>flu</code>、<code>measles</code>、<code>mumps</code>等词连用</p><p>e.g. <code>He&#39;s got the flu.</code></p></li></ul><p><code>have</code>的另外三种用法参考<a href="#lesson-59-60">59~60课</a>、<a href="#lesson-81-82">81~82课</a>和<a href="#lesson-87-88">87~88课</a></p></div><h2 id="lesson-63-64" tabindex="-1">Lesson 63~64 <a class="header-anchor" href="#lesson-63-64" aria-label="Permalink to &quot;Lesson 63~64&quot;">​</a></h2><div class="danger custom-block"><p class="custom-block-title">⚡本课重点</p><p><strong>must</strong>：参考之前的<a href="#lesson-29-30">29~30课</a></p><p><strong>so</strong></p><ul><li><p>作为程度副词时，用于形容词或副词的前面，表示「<strong>如此</strong>」</p><p>e.g. <code>She is so beautiful.</code></p></li><li><p>作为转折连词时，表示「<strong>因此</strong>」</p><p>e.g. <code>You have flu so you must stay at home.</code></p></li></ul><p><strong>because</strong>：单词本义为「<strong>因为</strong>」，它和<code>so</code>之间的关系如下</p><ul><li><p>用了<strong>因为</strong>就不能用<strong>所以</strong>，用了<strong>所以</strong>就不能用<strong>因为</strong></p><p>e.g. <code>You must stay at home because you have flu.</code> =&gt; <code>You have flu so you must stay at home.</code></p></li></ul><hr><p><strong>wake up</strong>：表示「<strong>醒来</strong>」</p><p><strong>get up</strong>：表示「<strong>起床</strong>」</p></div><h2 id="lesson-65-66" tabindex="-1">Lesson 65~66 <a class="header-anchor" href="#lesson-65-66" aria-label="Permalink to &quot;Lesson 65~66&quot;">​</a></h2><div class="danger custom-block"><p class="custom-block-title">⚡本课重点</p><p><strong>反身代词</strong>：关于各人称代词所对应的反身代词，可以参考<a href="./../basic_concept.html#人称代词">基础概念</a>中的人称代词</p><ul><li><p>当宾语和主语是同一个人时，一般需要用反身代词</p><p>e.g. <code>The old lady is talking to herself.</code></p></li><li><p>反身代词也可以和名词连用，表达「<strong>就是那个人而不是别人</strong>」</p><p>e.g. <code>They wanted to finish the work themselves.</code></p></li></ul><hr><p><strong>dad和mum</strong>：它们前面如果没有「所有格代词」或「名词所有格」作修饰的话，就特指自己的父母，此时要大写开头</p><p><strong>this、next、every等词开头的时间状语前面通常不加介词</strong></p><p><strong>want to do sth.</strong>：想要做某事</p><p><strong>keep up with sb.</strong>：赶上某人</p><p><strong>keep on doing sth.</strong>：继续保持做某事</p><p><strong>cost和pay</strong></p><ul><li><strong>cost</strong>：物做主语，表示「某物的售价」</li><li><strong>pay</strong>：人做主语，表示「人为某物付钱」</li></ul></div><h2 id="lesson-67-68" tabindex="-1">Lesson 67~68 <a class="header-anchor" href="#lesson-67-68" aria-label="Permalink to &quot;Lesson 67~68&quot;">​</a></h2><h3 id="一般过去时" tabindex="-1">一般过去时 <a class="header-anchor" href="#一般过去时" aria-label="Permalink to &quot;一般过去时&quot;">​</a></h3><div class="danger custom-block"><p class="custom-block-title">⚡本课重点</p><table><thead><tr><th></th><th>be的现在时</th><th>be的过去时</th></tr></thead><tbody><tr><td>单数</td><td>am/is</td><td>was</td></tr><tr><td>复数</td><td>are</td><td>were</td></tr></tbody></table><p><strong>一般过去时</strong>：动作发生的时间是「<strong>过去</strong>」，动作没有具体的状态(<strong>零状态</strong>)，常常与表示动作完成的时间状语连用</p><p>本节课主要学习的是 <strong><code>主语</code>+<code>was/were</code>+<code>名词/形容词</code></strong> 句式的「<strong>主系表结构</strong>」一般过去时，这种句式的谓语是助动词<code>be</code>。在之后的<a href="#lesson-71-72">71~72课</a>中再学习 <strong><code>主语</code>+<code>V.ed</code></strong> 的「<strong>主谓宾结构</strong>」一般过去时</p><p><strong>主系表结构一般过去时</strong>：助动词<code>be</code>表示动作发生的时间</p><ul><li><p><strong>肯定句</strong>：<em>表示过去发生的动作、或存在的事实、状态</em>。<strong><code>主语</code>+<code>was/were</code>+<code>名词/形容词</code></strong></p><p>e.g. <code>I was a student.</code>、<code>We were at home in the morning.</code></p></li><li><p><strong>否定句</strong>：<em>只需在<code>be</code>的后面加上<code>not</code>即可</em>。<strong><code>主语</code>+<code>was/were</code>+<code>not</code>+<code>名词/形容词</code></strong></p><p>e.g. <code>He wasn&#39;t a teacher.</code>、<code>They were not at school.</code></p></li><li><p><strong>一般疑问句</strong>：<em>只需将<code>be</code>提到句首(主语前面)即可</em>。<strong><code>Was/Were</code>+<code>主语</code>+<code>名词/形容词</code></strong></p><p>e.g. <code>Was she hungry?</code>、<code>Were you happy?</code></p></li><li><p><strong>特殊疑问句</strong>：<em>在一般疑问句的句首加上特殊疑问词并去掉答案</em>。<strong><code>特殊疑问词</code>+<code>was/were</code>+<code>主语</code>+<code>名词/形容词</code></strong></p><p>e.g. <code>He was a teacher.</code> =&gt; <code>Was he a teacher?</code> =&gt; <code>What was he job?</code></p><p><em>先把陈述句中的<code>be</code>动词提到句首得到一般疑问句，再用<code>what</code>对一般疑问句中的答案<code>teacher</code>进行提问，并将其提到句首</em></p></li></ul><hr><p><strong>一般过去时常见的使用场景有</strong></p><ul><li><p>表示过去某一具体时间发生的动作或存在的事实、状态，常与表示明确的过去时间状语连用，如<code>a moment ago</code>、<code>yesterday</code>、<code>last night</code>、<code>last year</code>、<code>last night</code>等</p><p>e.g. <code>Mike was in China last year.</code></p></li><li><p>表示过去一段时间内经常性、习惯性的动作，常与<code>every day</code>、<code>usually</code>、<code>often</code>等时间状语连用</p></li><li><p>叙述没有具体的过去时间的动作或存在的状态</p><p>e.g. <code>They were at school.</code></p></li></ul><hr><p><strong>否定疑问句</strong>：<strong>谓语部分为否定形式的疑问句</strong>。表示说话者惊异的情绪、责难的口吻或赞叹；也可以表示说话者的某种建议、邀请、请求或看法等</p><p>这种句式主要是为了加强语气，尽管形式上是否的的，但却表示强有力的肯定</p><p>e.g. <code>Aren&#39;t you lucky.</code></p></div><h2 id="lesson-69-70" tabindex="-1">Lesson 69~70 <a class="header-anchor" href="#lesson-69-70" aria-label="Permalink to &quot;Lesson 69~70&quot;">​</a></h2><div class="danger custom-block"><p class="custom-block-title">⚡本课重点</p><p><strong>excited和exciting</strong>：都是由<code>excite</code>变化而来，单词本义为「<strong>兴奋、激动</strong>」</p><ul><li>以<code>-ing</code>结尾的形容词可以修饰「<strong>人或物</strong>」，表示「<strong>某人怎么样</strong>」或「<strong>某物令人感到...</strong>」</li><li>以<code>-ed</code>结尾的形容词修饰「<strong>人</strong>」，表示「<strong>某人对...感到怎么样</strong>」</li></ul><hr><p><strong>介词<code>at</code>、<code>on</code>、<code>in</code>的时间短语</strong></p><ul><li><p>介词<code>at</code>的时间短语通常表示「<strong>确切的时间</strong>」</p><p>e.g. <code>at 10 o&#39;clock</code>、<code>at lunchtime</code>、<code>at noon</code>、<code>at Christmas</code>、<code>at the age of 18</code></p></li><li><p>介词<code>on</code>常用于「<strong>周</strong>」、「<strong>月份中的任意一天</strong>」或「<strong>一天中的某段时间</strong>」</p><p>e.g. <code>on Monday</code>、<code>on April 1st</code>、<code>on Sunday morning</code>、<code>on your birthday</code>、<code>on Christmas Day</code></p></li><li><p>介词<code>in</code>的时间短语通常表示「<strong>某一段时间</strong>」</p><p>e.g. <code>in the evening</code>、<code>in March</code>、<code>in summer</code>、<code>in 1999</code>、<code>in the 20th century</code></p></li></ul></div><h2 id="lesson-71-72" tabindex="-1">Lesson 71~72 <a class="header-anchor" href="#lesson-71-72" aria-label="Permalink to &quot;Lesson 71~72&quot;">​</a></h2><h3 id="动词过去式变化" tabindex="-1">动词过去式变化 <a class="header-anchor" href="#动词过去式变化" aria-label="Permalink to &quot;动词过去式变化&quot;">​</a></h3><div class="danger custom-block"><p class="custom-block-title">⚡本课重点</p><p>在<a href="#lesson-67-68">67~68课</a>中学习的主要是「<strong>主系表结构</strong>」的一般过去时。而本节课则主要学习其「<strong>主谓宾结构</strong>」的一般过去时，核心结构是 <strong><code>主语</code>+<code>V.ed</code></strong>，它的谓语是实义动词<code>V.ed</code></p><p><strong>主谓宾结构一般过去时</strong>：隐式助动词<code>did</code>表示动作发生的时间</p><ul><li><p><strong>肯定句</strong>：<em>表示过去发生的动作、或存在的事实、状态</em>。<strong><code>主语</code>+<code>V.ed</code>(+<code>其他</code>)</strong></p><p>e.g. <code>I loved you.</code>、<code>He talked to me yesterday.</code>、<code>We played with our parents yesterday.</code></p></li><li><p><strong>否定句</strong>：<em>只需将实义动词改为原形并在其前面加上<code>did not</code>即可</em>。<strong><code>主语</code>+<code>did not</code>+<code>V.</code>(+<code>其他</code>)</strong></p><p>e.g. <code>I did not live in Beijing last year.</code>、<code>He didn&#39;t talk to me yesterday.</code></p></li><li><p><strong>一般疑问句</strong>：<em>只需将实义动词改为原形并把<code>did</code>加到句首(主语前面)即可</em>。<strong><code>Did</code>+<code>主语</code>+<code>V.</code>(+<code>其他</code>)</strong></p><p>e.g. <code>Did you love me?</code>、<code>Did he talk to me yesterday?</code></p></li><li><p><strong>特殊疑问句</strong>：<em>在一般疑问句的句首加上特殊疑问词并去掉答案</em>。<strong><code>特殊疑问词</code>+<code>did</code>+<code>主语</code>+<code>V.</code>(+<code>其他</code>)</strong></p><p>e.g. <code>He talked to me yesterday.</code> =&gt; <code>Did he talk to me yesterday?</code> =&gt; <code>What did he do yesterday?</code></p><p><em>先把陈述句中的<code>实义动词</code>改为原形，然后在句首加上<code>did</code>得到一般疑问句，最后用<code>what</code>对一般疑问句中的答案<code>talk to me</code>进行提问，并将其提到句首</em></p></li></ul><hr><p><strong>动词过去式和过去分词的变化</strong>：</p><ul><li><p>①一般的动词后面直接加<code>ed</code></p><ul><li><p>清辅音后面加<code>ed</code>时，读<code>/t/</code></p><p>e.g. <code>talk</code> =&gt; <code>talked</code></p></li><li><p>浊辅音或元音后面加<code>ed</code>时，读<code>/d/</code></p><p>e.g. <code>need</code> =&gt; <code>needed</code></p></li></ul></li><li><p>②以不发音的<code>e</code>结尾的动词，直接在词尾加<code>d</code></p><p>e.g. <code>love</code> =&gt; <code>loved</code>、<code>live</code> =&gt; <code>lived</code></p></li><li><p>③以辅音字母加<code>y</code>结尾的动词，变<code>y</code>为<code>i</code>再加<code>ed</code></p><p>e.g. <code>study</code> =&gt; <code>studied</code>、<code>carry</code> =&gt; <code>carried</code></p></li><li><p>④以元音字母加<code>y</code>结尾的动词，直接在词尾加<code>ed</code></p><p>e.g. <code>play</code> =&gt; <code>played</code></p></li><li><p>⑤以短元音加一个辅音字母结尾的动词(<em>往往以重读闭音节的形式出现，即<code>辅元辅</code></em>)，先双写这个辅音字母再加<code>ed</code></p><p>e.g. <code>stop</code> =&gt; <code>stopped</code>、<code>plan</code> =&gt; <code>planned</code></p></li><li><p>⑥以<code>ic</code>结尾的动词，直接在词尾加<code>ked</code></p><p>e.g. <code>traffic</code> =&gt; <code>trafficked</code>、<code>picnic</code> =&gt; <code>picnicked</code></p></li><li><p>⑦不规则变化</p><p>e.g. <code>do</code> =&gt; <code>did</code>、<code>say</code> =&gt; <code>said</code></p></li></ul><hr><p><strong>time</strong></p><ul><li><p>作为不可数名词时，表示「<strong>时间</strong>」</p></li><li><p>作为可数名词时，表示「<strong>次数</strong>」。3次或3次以上时，通常用<code>数词</code>+<code>times</code></p><p>e.g. <code>once</code>、<code>twice</code>、<code>three times</code></p></li></ul><p><strong>speak to sb.</strong>：表示「<strong>与某人说话</strong>」</p></div><h2 id="lesson-73-74" tabindex="-1">Lesson 73~74 <a class="header-anchor" href="#lesson-73-74" aria-label="Permalink to &quot;Lesson 73~74&quot;">​</a></h2><h3 id="形容词变副词" tabindex="-1">形容词变副词 <a class="header-anchor" href="#形容词变副词" aria-label="Permalink to &quot;形容词变副词&quot;">​</a></h3><div class="danger custom-block"><p class="custom-block-title">⚡本课重点</p><p><strong>副词</strong>：它在句子中的作用是「<strong>修饰动词作状语</strong>」。它对动词进行补充说明，告诉我们所修饰的动词在句子中的<strong>动作的状态、程度</strong>。副词可以是单个的词或词组</p><p><strong>形容词变副词的规则</strong></p><ul><li><p>①一般情况下直接在词尾加<code>ly</code></p><p>e.g. <code>quick</code> =&gt; <code>quickly</code>、<code>pleasant</code> =&gt; <code>pleasantly</code></p></li><li><p>②以辅音字母加<code>y</code>结尾</p><ul><li><p>词尾<code>y</code>的发音为<code>/i/</code>的形容词，变<code>y</code>为<code>i</code>再加<code>ly</code></p><p>e.g. <code>happy</code> =&gt; <code>happily</code>、<code>thirsty</code> =&gt; <code>thirstily</code></p></li><li><p>词尾<code>y</code>的发音为<code>/ai/</code>的形容词，直接在词尾加<code>ly</code></p></li></ul></li><li><p>③以辅音字母加<code>le</code>结尾的形容词，变<code>e</code>为<code>y</code></p><p>e.g. <code>simple</code> =&gt; <code>simply</code></p></li><li><p>④以不发音的<code>e</code>结尾的形容词，去掉<code>e</code>后再加<code>ly</code></p><p>e.g. <code>true</code> =&gt; <code>truly</code></p></li><li><p>⑤以<code>ic</code>结尾的形容词，直接在词尾加<code>ally</code></p><p>e.g. <code>economic</code> =&gt; <code>economically</code></p></li><li><p>⑥以<code>ll</code>结尾的形容词，直接在词尾加<code>y</code></p><p>e.g. <code>dull</code> =&gt; <code>dully</code></p></li><li><p>⑦形容词和副词同形</p><p>e.g. <code>hard</code>、<code>well</code></p></li></ul></div><h2 id="lesson-75-76" tabindex="-1">Lesson 75~76 <a class="header-anchor" href="#lesson-75-76" aria-label="Permalink to &quot;Lesson 75~76&quot;">​</a></h2><h3 id="陈述句宾语从句" tabindex="-1">陈述句宾语从句 <a class="header-anchor" href="#陈述句宾语从句" aria-label="Permalink to &quot;陈述句宾语从句&quot;">​</a></h3><div class="danger custom-block"><p class="custom-block-title">⚡本课重点</p><p>本节课先主要学习<strong>陈述句做宾语从句</strong>的相关概念和基础知识，往后的<a href="#lesson-99-100">99~100课</a>和<a href="#lesson-133-134">133~136课</a>还会巩固学习这方面的知识</p><p><strong>宾语从句</strong>：一个句子来充当宾语就叫做<strong>宾语从句</strong>。主句和从句之间用<code>that</code>连接，但<code>that</code>是可以被省略的。<strong>当主句是一般现在时，从句可以用任何时态</strong></p><ul><li><p>跟在表示人的情感或心理活动的<strong>形容词</strong>后面。<strong><code>主语</code>+<code>be</code>+<code>形容词</code>(+<code>that</code>)+<code>从句</code></strong></p><p>e.g. <code>I&#39;m afraid that I can&#39;t come tomorrow.</code>、<code>I&#39;m glad that you can help them.</code></p></li><li><p>跟在<strong>普通动词</strong>后面。<strong><code>主语</code>+<code>V</code>(+<code>that</code>)+<code>从句</code></strong></p><p>e.g. <code>I think that you are right.</code>、<code>She knows that you will come.</code></p></li></ul><hr><p><strong>给某人买某物</strong></p><ul><li><p><code>buy sth. for sb.</code></p><p>e.g. <code>I bought a book for my sister 2 weeks ago.</code></p></li><li><p><code>buy sb. sth.</code></p><p>e.g. <code>She bought her boyfriend a watch.</code></p></li></ul></div><h2 id="lesson-77-78" tabindex="-1">Lesson 77~78 <a class="header-anchor" href="#lesson-77-78" aria-label="Permalink to &quot;Lesson 77~78&quot;">​</a></h2><div class="danger custom-block"><p class="custom-block-title">⚡本课重点</p><p>在之前的<a href="#lesson-69-70">69~70课</a>已经初步了解了<code>at</code>、<code>on</code>、<code>in</code>三者在时间表示上的区别，本节课继续做补充</p><p><strong>at用于小地点或钟点时刻的前面</strong></p><p>e.g. <code>at home</code>、<code>at six o&#39;clock</code></p><p><strong>on用于星期的前面或一个月中的具体某一天</strong></p><p>e.g. <code>on Monday</code>、<code>on April 1st</code></p><p><strong>in用于月份、季节、国家或大地点的前面</strong></p><p>e.g. <code>in March</code>、<code>in sumber</code>、<code>in China</code>、<code>in Beijing</code></p></div><h2 id="lesson-79-80" tabindex="-1">Lesson 79~80 <a class="header-anchor" href="#lesson-79-80" aria-label="Permalink to &quot;Lesson 79~80&quot;">​</a></h2><h3 id="have-got" tabindex="-1">have got <a class="header-anchor" href="#have-got" aria-label="Permalink to &quot;have got&quot;">​</a></h3><div class="danger custom-block"><p class="custom-block-title">⚡本课重点</p><p><strong>have和have got</strong>：两者所表达的意思相同，都是「<strong>有</strong>」。<code>have got</code>通常用于口语中，在「<strong>过去时态</strong>」和「<strong>重复动作</strong>」这两种情况下，<code>have/has got</code>不能代替<code>have</code></p><p>e.g. <code>I have a car.</code>=<code>I have got a car.</code></p><p><strong>注意，虽然have got在形式上看起来和现在完成时的结构很像，但have got并不属于现在完成时</strong></p><ul><li><p><strong>肯定句</strong>：<em>表示某人有某物</em>。<strong><code>主语</code>+<code>have/has got</code>+<code>其他</code></strong></p><p>e.g. <code>I have got a car.</code>=<code>I&#39;ve got a car.</code>、<code>He has got a car.</code>=<code>He&#39;s got a car.</code></p></li><li><p><strong>否定句</strong>：<em>直接在<code>have或has</code>的后面加上<code>not</code>即可，也可以用助动词<code>do/does</code></em>。<strong><code>主语</code>+<code>haven&#39;t/hasn&#39;t got</code>+<code>其他</code></strong></p><p>e.g. <code>I haven&#39;t got a car.</code>=<code>I don&#39;t have a car.</code>、<code>He hasn&#39;t got a car.</code>=<code>He doesn&#39;t have a car.</code></p></li><li><p><strong>一般疑问句</strong>：<em>只需将<code>have或has</code>提到句首(主语前面)即可，也可以用助动词<code>do/does</code></em>。<strong><code>Have/Has</code>+<code>主语</code>+<code>got</code>+<code>其他</code></strong></p><p>e.g. <code>Have you got a car?</code>=<code>Do you have a car?</code>、<code>Has he got a car?</code>=<code>Does he have a car?</code></p></li><li><p><strong>特殊疑问句</strong>：<em>在一般疑问句的句首加上特殊疑问词并去掉答案</em>。<strong><code>特殊疑问词</code>+<code>have/has</code>+<code>主语</code>+<code>got</code>+<code>其他</code></strong></p><p>e.g. <code>I have got a car.</code> =&gt; <code>Have you got a car?</code> =&gt; <code>What have you got?</code>=<code>What do you have?</code></p><p><em>先把陈述句中的<code>have</code>提到句首得到一般疑问句，再用<code>what</code>对一般疑问句中的答案<code>a car</code>进行提问，并将其提到句首</em></p></li></ul><hr><p><strong>need</strong>：单词本义为「<strong>需要</strong>」</p><ul><li><p>当作为情态动词时，没有人称、数和时态上的变化，可以直接对其加<code>not</code>构成否定形式，常用于否定和疑问句中。<strong><code>need</code>+<code>V.</code></strong></p><p>e.g. <code>You needn&#39;t hurry.</code>、<code>Need I make an appointment?</code></p></li><li><p>当作为实义动词时，就要有人称、数和时态上的变化，能用在各种句式中，否定和疑问句时需要用助动词<code>do/does</code>。<strong><code>need</code>(+<code>to</code>)+<code>V.</code></strong></p><p>e.g. <code>He needs some rest.</code>、<code>I don&#39;t need to rest.</code>、<code>Do you need to rest?</code></p></li></ul><hr><p><strong>much和many</strong>：都表示「<strong>许多</strong>」</p><ul><li><p><strong>much</strong>：修饰不可数名词，用在否定和疑问句中</p><p>e.g. <code>There isn&#39;t much tea on the table.</code>、<code>How much money do you want?</code></p></li><li><p><strong>many</strong>：修饰可数名词，能用在各种句式中</p><p>e.g. <code>There are many cars in the park?</code>、<code>There aren&#39;t many dishes in the kitchen?</code>、<code>How many photos did you take?</code></p></li></ul><p><strong>a lot of</strong>：表示「<strong>许多</strong>」。既可修饰可数名词，也可以修饰不可数名词，能用在各种句式中</p><p>e.g. <code>I&#39;ve got a lot of money.</code>、<code>We&#39;ve got a lot of apples.</code>、<code>He hasn&#39;t got a lot of free time.</code></p><p>转换为在否定和疑问句</p><ul><li><p>如果<code>a lot of</code>后面跟可数名词，则把<code>a lot of</code>换成<code>many</code></p><p>e.g. <code>I&#39;ve got a lot of friends.</code> =&gt; <code>I haven&#39;t got many friends.</code> =&gt; <code>Have you got many friends?</code></p></li><li><p>如果<code>a lot of</code>后面跟不可数名词，则把<code>a lot of</code>换成<code>much</code></p><p>e.g. <code>I&#39;ve got a lot of money.</code> =&gt; <code>I haven&#39;t got much money.</code> =&gt; <code>Have you got much money?</code></p></li></ul></div><h2 id="lesson-81-82" tabindex="-1">Lesson 81~82 <a class="header-anchor" href="#lesson-81-82" aria-label="Permalink to &quot;Lesson 81~82&quot;">​</a></h2><h3 id="have用法3" tabindex="-1">have用法③ <a class="header-anchor" href="#have用法3" aria-label="Permalink to &quot;have用法③&quot;">​</a></h3><div class="danger custom-block"><p class="custom-block-title">⚡本课重点</p><p><strong>have用法③</strong>：<strong><code>have</code>(+<code>a</code>)+<code>名词</code></strong>，作用是将名词「<strong>动词化</strong>」。其中<code>have</code>作为实义动词使用，可以代替一些常用动词，例如<code>eat</code>、<code>enjoy</code>、<code>drink</code>、<code>take</code>等。这时它就有各种时态上的变化了</p><ul><li>现在进行时(<code>be V.ing</code>)：<code>I&#39;m having lunch.</code>、<code>She&#39;s having a bath.</code></li><li>一般现在时(<code>have/has</code>)：<code>I have a bath every night.</code>、<code>She has breakfast every morning.</code><ul><li><em>否定句和疑问句时必须用<code>do/does</code></em>：<code>Does he have lessons on Friday?</code>、<code>He doesn&#39;t have lessons on Friday.</code></li></ul></li><li>一般过去时(<code>had</code>)：<code>I had a meeting 2 hours ago.</code>、<code>He had a party last night.</code><ul><li><em>否定句和疑问句时必须用<code>did</code></em>：<code>Did you have lunch?</code>、<code>We didn&#39;t have lunch.</code></li></ul></li><li>一般将来时(<code>be going to V.</code>)：<code>I&#39;m going to have a bath tonight.</code></li></ul><p><em>因为到本节课为止只学了这四个时态，所以先只列出这四个时态的用法</em></p><p><code>have</code>的另外三种用法参考<a href="#lesson-59-60">59~60课</a>、<a href="#lesson-61-62">61~62课</a>和<a href="#lesson-87-88">87~88课</a></p></div><h2 id="lesson-83-84" tabindex="-1">Lesson 83~84 <a class="header-anchor" href="#lesson-83-84" aria-label="Permalink to &quot;Lesson 83~84&quot;">​</a></h2><h3 id="现在完成时" tabindex="-1">现在完成时 <a class="header-anchor" href="#现在完成时" aria-label="Permalink to &quot;现在完成时&quot;">​</a></h3><div class="danger custom-block"><p class="custom-block-title">⚡本课重点</p><p><strong>现在完成时</strong>：动作发生的时间是「<strong>过去</strong>」，动作的状态是「<strong>完成</strong>」。核心结构 <strong><code>have/has</code>+<code>V.pp.</code></strong></p><p>此时的<code>have/has</code>在句中的功能类似「<strong>主系表结构</strong>」中的<code>be</code>动词，用来表示动作发生的时间，而<code>过去分词</code>表示动作的状态。现在完成时<strong>不能</strong>与表示动作完成的具体时间连用</p><p><strong>用法①</strong>：「<strong>言之过去，意在当下</strong>」。大白话讲就是在过去不确定的时间里发生的并与现在有着某种联系的动作。在之后的<a href="#lesson-89-90">89~90课</a>会学习其另一种用法</p><p>翻译时需要根据上下文语境和场景，才能知道现在完成时所要表达的真实意思。例如，<code>Do you want to have some food? No, thanks, I have just had some food.</code>，使用现在完成时来回答，字面意思是「我刚才吃过了」，但根据上下文语境，真正想表达的是「我刚才吃过了，肚子很饱，现在吃不下了」</p><ul><li><p><strong>肯定句</strong>：<strong><code>主语</code>+<code>have/has</code>+<code>V.pp.</code>+<code>其他</code></strong></p><p>e.g. <code>I&#39;ve packed my bag.</code>、<code>He has lost his key.</code></p></li><li><p><strong>否定句</strong>：<em>直接在<code>have或has</code>的后面加上<code>not</code>即可</em>。<strong><code>主语</code>+<code>have/has</code>+<code>not</code>+<code>V.pp.</code>+<code>其他</code></strong></p><p>e.g. <code>I haven&#39;t packed my bag.</code>、<code>He hasn&#39;t lost his key.</code></p></li><li><p><strong>一般疑问句</strong>：<em>只需将<code>have或has</code>提到句首(主语前面)即可</em>。<strong><code>Have/Has</code>+<code>主语</code>+<code>V.pp.</code>+<code>其他</code></strong></p><p>e.g. <code>Have you packed your bag?</code>、<code>Has he lost his key?</code></p></li><li><p><strong>特殊疑问句</strong>：<em>在一般疑问句的句首加上特殊疑问词并去掉答案</em>。<strong><code>特殊疑问词</code>+<code>have/has</code>+<code>主语</code>+<code>V.pp.</code>+<code>其他</code></strong></p><p>e.g. <code>He has lost his key.</code> =&gt; <code>Has he lost his key?</code> =&gt; <code>What has he lost?</code></p><p><em>先把陈述句中的<code>has</code>提到句首得到一般疑问句，再用<code>what</code>对一般疑问句中的答案<code>his key</code>进行提问，并将其提到句首</em></p></li></ul><hr><p><strong>动词过去分词</strong>：过去分词的「规则变化」规律与动词过去式保持一致，在<a href="#lesson-71-72">71~72课</a>中已经学习过了。而「不规则变化」只能死记硬背，以后见到一个背一个</p><p><strong><code>&#39;s</code>缩写的几种情况</strong></p><ul><li><p>当<code>&#39;s</code>的后面跟着一个<code>名词</code>时，需要结合句子意思进行判断其到底是「<strong><code>is</code></strong>」还是「<strong>所有格</strong>」</p><p>e.g. <code>He&#39;s a student.</code>、<code>Tony&#39;s book is on the desk.</code></p></li><li><p>当<code>&#39;s</code>的后面跟着一个<code>V.ing</code>时，表示其为「<strong><code>is</code></strong>」</p><p>e.g. <code>He&#39;s doing his homework.</code></p></li><li><p>当<code>&#39;s</code>的后面跟着一个<code>got</code>或<code>动词过去分词</code>时，表示其为<code>have got</code>第三人称或现在完成时第三人称中的「<strong><code>has</code></strong>」</p><p>e.g. <code>He&#39;s got a car.</code>、<code>He&#39;s had lunch.</code></p></li></ul></div><h2 id="lesson-85-86" tabindex="-1">Lesson 85~86 <a class="header-anchor" href="#lesson-85-86" aria-label="Permalink to &quot;Lesson 85~86&quot;">​</a></h2><div class="danger custom-block"><p class="custom-block-title">⚡本课重点</p><p><strong>have/has gone</strong>：表示「<strong>去了</strong>」。去了某个地方(<em>可能在路上也可能已经到了</em>)，但是没有回来</p><p>e.g. <code>I went to Beijing last week and I am in Beijing now.</code> =&gt; <code>I have gone to Beijing.</code></p><p><strong>have/has been</strong>：表示「<strong>去过</strong>」。去了某个地方并且回来了</p><p>e.g. <code>Sally went to Paris last week and she arrived in Beijing yesterday.</code> =&gt; <code>She has been to Paris.</code></p><p><strong>ever</strong>：常用于否定句、疑问句，以及表示条件的从句</p><p>e.g. <code>Has George ever been to Paris?</code></p><p><strong>never ever</strong>：表示「<strong>永远</strong>」</p><p>e.g. <code>Never ever give up</code></p></div><h2 id="lesson-87-88" tabindex="-1">Lesson 87~88 <a class="header-anchor" href="#lesson-87-88" aria-label="Permalink to &quot;Lesson 87~88&quot;">​</a></h2><h3 id="动词不定式" tabindex="-1">动词不定式 <a class="header-anchor" href="#动词不定式" aria-label="Permalink to &quot;动词不定式&quot;">​</a></h3><div class="danger custom-block"><p class="custom-block-title">⚡本课重点</p><p><strong>have用法④</strong>：可以和具有动词和名词词性的动词搭配成词组。另外三种用法参考<a href="#lesson-59-60">59~60课</a>、<a href="#lesson-61-62">61~62课</a>和<a href="#lesson-81-82">81~82课</a></p><p>e.g. <code>have a look</code>、<code>have a rest</code>、<code>have a crash</code>、<code>have a swin</code>、<code>have a try</code>、<code>have a walk</code></p><hr><p><strong>动词不定式</strong>：是一种非谓语动词形式，它没有人称和数的变化，不能在句子中作谓语。其否定形式是在<code>to</code>的前面加<code>not</code></p><p>在英语中，当两个动词紧跟时，它们之间必须加一个不定式符号<code>to</code>。<strong>不定式符号后面的动词只能是原形</strong>，而不能是过去式或分词形式</p><ul><li>当然也是有特例情况的，有些动词是可以在<code>to</code>的前面加上<code>名词/宾格代词</code>的，即 <strong><code>动词</code>+<code>名词/宾格代词</code>+<code>to V.</code></strong></li></ul><p>e.g. <code>I want you to carry it.</code>、<code>Tell him to move it.</code></p><table><thead><tr><th></th><th>主动</th><th>被动</th></tr></thead><tbody><tr><td>一般式</td><td><code>to V.</code></td><td><code>to be V.pp.</code></td></tr><tr><td>进行式</td><td><code>to be V.ing</code></td><td></td></tr><tr><td>完成式</td><td><code>to have V.pp.</code></td><td><code>to have been V.pp.</code></td></tr><tr><td>完成进行式</td><td><code>to have been V.ing</code></td><td></td></tr></tbody></table><ul><li><p><strong>一般式</strong>：表示动作通常与谓语动词同时或几乎同时发生，又或是在它之后发生。核心结构为 <strong><code>to V.</code></strong></p><p>e.g. <code>He appears to be very happy.</code>、<code>She has decided to sell her car.</code></p></li><li><p><strong>进行式</strong>：表示正在进行的或与谓语动词同时发生的动作。核心结构为 <strong><code>to be V.ing</code></strong></p><p>e.g. <code>It happened to be raining when I got there.</code></p></li><li><p><strong>完成式</strong>：表示动作在谓语动词之前发生。核心结构为 <strong><code>to have V.pp.</code></strong></p><p>e.g. <code>I&#39;m sorry to have lost your key.</code></p></li><li><p><strong>完成进行式</strong>：表示动作在谓语动词之前发生并且一直进行着。核心结构为 <strong><code>to have been V.ing</code></strong></p><p>e.g. <code>He was said to have been living in London for twenty years.</code></p></li><li><p><strong>被动式</strong>：当不定式逻辑上的主语是这个不定式表示的动作的承受者时，不定式一般要用被动形式。被动式根据其与谓语动作发生的先后关系，有一般式和完成时两种</p><ul><li><p><strong>被动一般式</strong>：<strong><code>to be V.pp.</code></strong></p><p>e.g. <code>These are the books to be given out to the students.</code></p></li><li><p><strong>被动完成式</strong>：<strong><code>to have been V.pp.</code></strong></p><p>e.g. <code>The novel is said to have been translated into many languages.</code></p></li></ul></li></ul><hr><p><strong>修理的四种常见单词的区别</strong></p><ul><li><code>repair</code>：需要有一定的专业技能</li><li><code>fix</code>：和<code>repair</code>一样，但更多用在美语环境中</li><li><code>mend</code>：一般指修理结构较为简单的东西，不需要特殊的专业技能</li><li><code>do up</code>：修理结构更为简单的小东西，例如补衣服，补轮胎</li></ul><p><strong>receptionist和attendant</strong>：两者都表示「<strong>前台服务员</strong>」，但在日常生活中，<strong>receptionist</strong>的使用频率要比<strong>attendant</strong>高得多</p><p><strong>bring</strong>：表示「<strong>送来、带来、拿来</strong>」。在方位上多指朝着说话人而来</p><p><strong>yet</strong>：表示「<strong>直到现在</strong>」。用于否定句和疑问句中，通常出现在句尾</p><p>e.g. <code>The train hasn&#39;t left yet.</code>、<code>Have you started your new job yet?</code></p><p><strong>try to do sth</strong>：尝试做某事</p></div><h2 id="lesson-89-90" tabindex="-1">Lesson 89~90 <a class="header-anchor" href="#lesson-89-90" aria-label="Permalink to &quot;Lesson 89~90&quot;">​</a></h2><div class="danger custom-block"><p class="custom-block-title">⚡本课重点</p><p>在<a href="#lesson-83-84">83~84课</a>中学习了现在完成时的第一种用法，本节课来学习它的第二种用法</p><p><strong>现在完成时用法②</strong>：一个动作<code>done</code>或者状态<code>been</code>，从过去一直持续或重复到现在的动作或状态。这种用法常常与 <strong><code>for + 时间段</code></strong>(<em>表示持续多长时间</em>)或者 <strong><code>since + 时间点</code></strong>(<em>表示从何时开始</em>)连用。两种用法在结构上是一样的</p><ul><li><p><strong>肯定句</strong>： <strong><code>主语</code>+<code>have/has</code>+<code>V.pp.</code>+<code>其他</code></strong></p><p>e.g. <code>I&#39;ve lived in Beijing since 2008.</code>、<code>He&#39;s been working here for 5 years.</code></p></li><li><p><strong>否定句</strong>：<em>直接在<code>have或has</code>的后面加上<code>not</code>即可</em>。<strong><code>主语</code>+<code>have/has</code>+<code>not</code>+<code>V.pp.</code>+<code>其他</code></strong></p><p>e.g. <code>I haven&#39;t lived in Beijing since 2008.</code>、<code>He hasn&#39;t been working here for 5 years.</code></p></li><li><p><strong>一般疑问句</strong>：<em>只需将<code>have或has</code>提到句首(主语前面)即可</em>。<strong><code>Have/Has</code>+<code>主语</code>+<code>V.pp.</code>+<code>其他</code></strong></p><p>e.g. <code>Have you lived in Beijing scine 2008?</code>、<code>Has he worked here for 5 years?</code></p></li><li><p><strong>特殊疑问句</strong>：<em>在一般疑问句的句首加上<code>how long</code>，并去掉答案</em>。<strong><code>how long</code>+<code>have/has</code>+<code>主语</code>+<code>V.pp.</code>+<code>其他</code></strong></p><p>e.g. <code>I&#39;ve lived in Beijing since 2008.</code> =&gt; <code>Have you lived in Beijing scine 2008?</code> =&gt; <code>How long have you lived in Beijing?</code></p><p><em>先把陈述句中的<code>have</code>提到句首得到一般疑问句，再用<code>how long</code>对一般疑问句中的答案<code>scine 2008</code>进行提问，并将其提到句首</em></p></li></ul></div><h2 id="lesson-91-92" tabindex="-1">Lesson 91~92 <a class="header-anchor" href="#lesson-91-92" aria-label="Permalink to &quot;Lesson 91~92&quot;">​</a></h2><div class="danger custom-block"><p class="custom-block-title">⚡本课重点</p><p>本节课要学习的是 <strong><code>will/shall</code>+<code>V.</code></strong> 结构的一般将来时。在之前的<a href="#lesson-37-38">37~38课</a>中学习了 <strong><code>be</code>+<code>going to</code>+<code>V.</code></strong> 结构的一般将来时</p><p><strong>一般将来时</strong>：动作发生的时间是「<strong>将来</strong>」，动作没有具体的状态(<strong>零状态</strong>)。表示打算、将来要做的事情或将要发生的事情，常与表示将来意义的时间状语连用</p><p><strong>注意，其中的<code>will</code>可用于所有人称，而<code>shall</code>只能用于第一人称<code>I</code>和<code>we</code></strong></p><ul><li><p><strong>肯定句</strong>：<strong><code>主语</code>+<code>will/shall</code>+<code>V.</code>+<code>其他</code></strong></p><p>e.g. <code>I&#39;ll miss you.</code>、<code>I shall answer the phone.</code>、<code>Tom will be late.</code></p></li><li><p><strong>否定句</strong>：<em>直接在<code>will或shall</code>的后面加上<code>not</code>即可</em>。<strong><code>主语</code>+<code>will/shall</code>+<code>not</code>+<code>V.</code>+<code>其他</code></strong></p><p>e.g. <code>I won&#39;t miss you.</code>、<code>I shan&#39;t answer the phone.</code>、<code>They won&#39;t get married.</code></p></li><li><p><strong>一般疑问句</strong>：<em>只需将<code>will或shall</code>提到句首(主语前面)即可</em>。<strong><code>Will/Shall</code>+<code>主语</code>+<code>V.</code>+<code>其他</code></strong></p><p>e.g. <code>Will you miss me?</code>、<code>Shall I answer the phone?</code></p></li><li><p><strong>特殊疑问句</strong>：<em>在一般疑问句的句首加上特殊疑问词并去掉答案</em>。<strong><code>特殊疑问词</code>+<code>will/shall</code>+<code>主语</code>+<code>V.</code>+<code>其他</code></strong></p><p>e.g. <code>I&#39;ll miss you.</code> =&gt; <code>Will you miss me?</code> =&gt; <code>Who will you miss?</code></p><p><em>先把陈述句中的<code>will</code>提到句首，并进行人称调整以符合语义，从而得到一般疑问句，再用<code>who</code>对一般疑问句中的答案<code>me</code>进行提问，并将其提到句首</em></p></li></ul><p><strong>但注意，<code>will</code>不用来表示事先安排好或决定做的事情</strong></p><hr><p><strong>person和people</strong>：都表示「<strong>人</strong>」</p><ul><li><code>person</code>是单数形式，<code>He is a person.</code></li><li><code>people</code>是复数形式，<code>They are people.</code></li></ul></div><h2 id="lesson-93-94" tabindex="-1">Lesson 93~94 <a class="header-anchor" href="#lesson-93-94" aria-label="Permalink to &quot;Lesson 93~94&quot;">​</a></h2><div class="danger custom-block"><p class="custom-block-title">⚡本课重点</p><p><strong>before last</strong>：上一个</p><p>e.g. <code>the week before last</code> =&gt; 前一周</p><p><strong>after next</strong>：下一个</p><p>e.g. <code>the year after next</code> =&gt; 后年</p></div><h2 id="lesson-95-96" tabindex="-1">Lesson 95~96 <a class="header-anchor" href="#lesson-95-96" aria-label="Permalink to &quot;Lesson 95~96&quot;">​</a></h2><h3 id="had-better" tabindex="-1">had better <a class="header-anchor" href="#had-better" aria-label="Permalink to &quot;had better&quot;">​</a></h3><div class="danger custom-block"><p class="custom-block-title">⚡本课重点</p><p><strong>had better</strong>：表示「<strong>最好、最好还是</strong>」，常用来表达某种忠告或建议，用在现在时或将来时中，后面跟动词原形</p><p>这里的<code>had</code>并非表示过去时态，而是英语的一种语言习惯，是一种<strong>固定搭配用法</strong></p><ul><li><p><strong>肯定句</strong>：<strong><code>主语</code>+<code>had better</code>+<code>V.</code>+<code>其他</code></strong></p><p>e.g. <code>You&#39;d better sleep.</code></p></li><li><p><strong>否定句</strong>：<em>直接在<code>had better</code>的后面加上<code>not</code>即可</em>。<strong><code>主语</code>+<code>had better</code>+<code>not</code>+<code>V.</code>+<code>其他</code></strong></p><p>e.g. <code>You&#39;d better not do that.</code></p></li></ul><p><strong>in xxx time</strong>：表示「<strong>在...之后</strong>」。单数时用<code>&#39;s</code>，复数时用<code>s&#39;</code>。后面的<code>time</code>可以省略</p><p>e.g. <code>in an hour&#39;s time</code>、<code>in three days&#39; time</code>、<code>in two weeks&#39; time</code></p><p><strong>plenty of</strong>：表示「<strong>大量</strong>」，后面可以跟可数和不可数名词，只能用于肯定句</p><p>e.g. <code>We&#39;ve got plenty of time.</code></p></div><h2 id="lesson-97-98" tabindex="-1">Lesson 97~98 <a class="header-anchor" href="#lesson-97-98" aria-label="Permalink to &quot;Lesson 97~98&quot;">​</a></h2><div class="danger custom-block"><p class="custom-block-title">⚡本课重点</p><p><strong>belong to sb</strong>：表示「<strong>属于某人</strong>」，单数的时候<code>belong</code>后面加<code>s</code>，复数时不用加</p><p>e.g. <code>This is my book.</code> =&gt; <code>This book belongs to me.</code>、<code>These are our letters.</code> =&gt; <code>They belong to us.</code></p></div><h2 id="lesson-99-100" tabindex="-1">Lesson 99~100 <a class="header-anchor" href="#lesson-99-100" aria-label="Permalink to &quot;Lesson 99~100&quot;">​</a></h2><div class="danger custom-block"><p class="custom-block-title">⚡本课重点</p><p><strong>宾语从句</strong>：参考之前的<a href="#lesson-75-76">75~76课</a></p><p><strong>直接引语</strong>：把别人的原话加上引号进行复述</p><p>e.g. <code>The doctor says, &quot;I will come at once.&quot;</code></p><p><strong>间接引语</strong>：把别人的原话进行人称转换后再说一遍，大白话就是「用自己的话来转述别人说的话」。间接引语其实就是宾语从句，<strong>它的动词与主句中的主要动词在时态上必须保持一致</strong></p><p>e.g. <code>The doctor says that he will come at once.</code></p><p><strong>直接引语变间接引语的步骤</strong></p><ul><li>①去掉引号</li><li>②转换人称</li><li>③添加引导词<code>that</code></li></ul><hr><p><strong>help sb. (to) do sth.</strong>：帮某人做某事</p><p><strong>offer help to sb.</strong>：给某人提供帮助</p><p><strong>provide help to sb.</strong>：给某人提供(免费的)帮助</p></div><h2 id="lesson-101-102" tabindex="-1">Lesson 101~102 <a class="header-anchor" href="#lesson-101-102" aria-label="Permalink to &quot;Lesson 101~102&quot;">​</a></h2><h3 id="反意疑问句" tabindex="-1">反意疑问句 <a class="header-anchor" href="#反意疑问句" aria-label="Permalink to &quot;反意疑问句&quot;">​</a></h3><div class="danger custom-block"><p class="custom-block-title">⚡本课重点</p><p><strong>反意疑问句</strong>：用来询问某种情况是否真实，或者别人是否同意自己。它的组成分为两部分：<strong>逗号前面为主句，后面为反意疑问句</strong>。在口语中，逗号后的问句可以用<code>right?</code>代替</p><ul><li><p>当前面是肯定句时，后面就是否定句</p><p>e.g. <code>Sally can speak French, can&#39;t she?</code></p></li><li><p>当前面是否定句时，后面就是肯定句</p><p>e.g. <code>Sally can&#39;t speak French, can she?</code></p></li></ul><p><strong>其特点为</strong>：</p><ul><li>问句的主语和主句的主语一致</li><li>前后的助动词一致</li><li>前后的时态一致</li></ul><p><strong>在语调上的区别</strong>：</p><ul><li><strong>升调</strong>：表示疑问，期待对方回答</li><li><strong>降调</strong>：表示确定，不需要回答</li></ul></div><h2 id="lesson-103-104" tabindex="-1">Lesson 103~104 <a class="header-anchor" href="#lesson-103-104" aria-label="Permalink to &quot;Lesson 103~104&quot;">​</a></h2><div class="danger custom-block"><p class="custom-block-title">⚡本课重点</p><p><strong>程度副词</strong>：<code>too</code> &gt; <code>very</code> &gt; <code>enough</code></p><p><strong>too</strong>：用于表示程度时，其意思为「<strong>太、过于</strong>」</p><ul><li><p>可以用在 <strong><code>too adj.</code>(+<code>for sb.</code>)+<code>to V. sth.</code></strong> 结构中</p><p>e.g. <code>This skirt is too big for me.</code>、<code>The wall is too high for me to climb.</code>、<code>She is too young to live alone.</code></p></li></ul><p><strong>enough</strong>：单词本义为「<strong>足够</strong>」</p><ul><li><p>在形容词之后使用，<strong><code>adj.</code>+<code>enough</code>(+<code>for sb.</code>)+<code>to V.</code></strong></p><p>e.g. <code>He failed the exam because it wasn&#39;t easy enough.</code>、<code>She is old enough to get married.</code>、<code>This question is easy enough for me to answer.</code></p></li><li><p>在名词之前使用</p><p>e.g. <code>We don&#39;t have enough money.</code></p></li><li><p>可以用在 <strong><code>enough ... for sb./sth.</code></strong> 或 <strong><code>enough ... to V. sth.</code></strong> 结构中</p><p>e.g. <code>She hasn&#39;t got enough money for a holiday.</code>、<code>She isn&#39;t old enough to live alone.</code>、<code>There isn&#39;t nearly enough time to get there now</code></p></li></ul><hr><p><strong>could</strong>：<code>can</code>的过去式，用法和<code>can</code>几乎一样，具体参考<a href="#lesson-43-44">43~44课</a></p><p><strong>hate to do sth.</strong>：讨厌做某事(一次性的)</p><p><strong>hate doing sth.</strong>：讨厌做某事(经常性的)</p></div><h2 id="lesson-105-106" tabindex="-1">Lesson 105~106 <a class="header-anchor" href="#lesson-105-106" aria-label="Permalink to &quot;Lesson 105~106&quot;">​</a></h2><div class="danger custom-block"><p class="custom-block-title">⚡本课重点</p><p><strong>动词不定式</strong>：具体参考<a href="#lesson-87-88">87~88课</a></p><p><strong>be full of</strong>：一种习惯用法，表示「<strong>充满</strong>」</p><p>e.g. <code>He is full of energy.</code>、<code>Your story is full of mistakes.</code></p><p><strong>want to do sth.</strong>：想要做某事，在口语中，常常把<code>want to</code>说成<code>wanna</code>，即<code>wanna do sth.</code></p><p>e.g. <code>I want to buy a new car.</code> =&gt; <code>I wanna buy a new car.</code></p><p><strong>tell sb. to do sth.</strong>：告诉某人做某事</p><p>e.g. <code>Please tell him to bring me some coffee.</code></p></div><h2 id="lesson-107-108" tabindex="-1">Lesson 107~108 <a class="header-anchor" href="#lesson-107-108" aria-label="Permalink to &quot;Lesson 107~108&quot;">​</a></h2><h3 id="比较级和最高级" tabindex="-1">比较级和最高级 <a class="header-anchor" href="#比较级和最高级" aria-label="Permalink to &quot;比较级和最高级&quot;">​</a></h3><div class="danger custom-block"><p class="custom-block-title">⚡本课重点</p><p><strong>形容词的比较级和最高级</strong>：以<code>er</code>结尾的形容词属于「<strong>比较级</strong>」，而以<code>est</code>结尾的形容词属于「<strong>最高级</strong>」</p><p><strong>其变化规则如下</strong></p><ul><li><p>①一般情况下，单音节形容词的词尾直接加<code>er/est</code></p><p>e.g. <code>small</code> =&gt; <code>smaller</code> =&gt; <code>smallest</code>、<code>new</code> =&gt; <code>newer</code> =&gt; <code>newest</code></p></li><li><p>②以<code>e</code>结尾的形容词，直接在词尾加<code>r/st</code></p><p>e.g. <code>nice</code> =&gt; <code>nicer</code> =&gt; <code>nicest</code>、<code>large</code> =&gt; <code>larger</code> =&gt; <code>largest</code></p></li><li><p>③以辅音字母加<code>y</code>结尾的形容词，将<code>y</code>改为<code>i</code>，再加<code>er/est</code></p><p>e.g. <code>easy</code> =&gt; <code>easier</code> =&gt; <code>easiest</code>、<code>heavy</code> =&gt; <code>heavier</code> =&gt; <code>heaviest</code></p></li><li><p>④当单音节形容词只有一个元音字母，并且以一个辅音字母结尾时(<em>往往以重读闭音节的形式出现，即<code>辅元辅</code></em>)，先双写词尾辅音字母再加<code>er/est</code></p><p>e.g. <code>big</code> =&gt; <code>bigger</code> =&gt; <code>biggest</code>、<code>thin</code> =&gt; <code>thinner</code> =&gt; <code>thinnest</code></p></li><li><p>⑤不规则变化</p><p>e.g. <code>good/well</code> =&gt; <code>better</code> =&gt; <code>best</code>、<code>bad/ill</code> =&gt; <code>worse</code> =&gt; <code>worst</code>、<code>little</code> =&gt; <code>less</code> =&gt; <code>least</code>、<code>many/much</code> =&gt; <code>more</code> =&gt; <code>most</code></p></li><li><p>⑥大多数较长的形容词(<em>即有两个以上音节的词</em>)可与<code>more/less</code>连用构成比较级，与<code>most/least</code>连用构成最高级</p><p>e.g. <code>She&#39;s more beautiful than her sister.</code>、<code>She&#39;s the most beautiful in her class.</code></p></li></ul><p><strong>用法</strong>：</p><ul><li><p>比较级<strong>只用于两者之间</strong>，通常与<code>than</code>连用，结构为 <strong><code>主语</code>+<code>be</code>+<code>adj.er</code>+<code>than</code>+<code>比较对象</code></strong>。如果所指代事物很明确，也可以独立存在</p><p>e.g. <code>He&#39;s taller than his father.</code>、<code>I haven&#39;t got a larger dress.</code></p></li><li><p>最高级<strong>用于三者或以上</strong>的情况，在使用时必须加定冠词<code>the</code>，并常伴有一个表示范围的介词短语或从句，其常见结构如下</p><ul><li><p><strong><code>主语</code>+<code>be</code>+<code>the</code>+<code>adj.est</code>(+<code>n.</code>)+<code>范围</code></strong></p><p>e.g. <code>That girl is the tallest student in our class.</code></p></li><li><p><strong><code>主语</code>+<code>be</code>+<code>the</code>+<code>adj.est</code>(+<code>n.</code>)+<code>I&#39;ve ever V.pp.</code></strong></p><p>e.g. <code>This is the craziest thing I&#39;ve ever done.</code></p></li></ul></li><li><p><strong>排除自己</strong>：使用<code>other</code></p><p>e.g. <code>He&#39;s taller than any other students in his class</code>、<code>Shanghai is larger than other cities in China.</code></p></li></ul><hr><p><strong>would</strong>：<code>will</code>的过去式，表示「<strong>愿意</strong>」。常常与<code>like</code>连用构成<code>would like</code>，缩写形式为<code>&#39;d like</code></p><ul><li><p><strong><code>would like</code>+ <code>n.</code></strong>：愿意尝试某物/事</p><p>e.g. <code>I would like some tea.</code> =&gt; <code>I&#39;d like some tea.</code></p></li><li><p><strong><code>would like</code>+<code>to do sth.</code></strong>：愿意做某事</p><p>e.g. <code>I would like to help him.</code></p></li></ul></div><h2 id="lesson-109-110" tabindex="-1">Lesson 109~110 <a class="header-anchor" href="#lesson-109-110" aria-label="Permalink to &quot;Lesson 109~110&quot;">​</a></h2><div class="danger custom-block"><p class="custom-block-title">⚡本课重点</p><p><strong>不可数名词的多与少，用<code>much</code>和<code>little</code>来表达；可数名词的多与少，用<code>many</code>和<code>few</code>来表达</strong>。在之前的<a href="#lesson-79-80">79~80课</a>中学习了<code>much</code>和<code>many</code>的用法，本节课来学习<code>little</code>和<code>few</code></p><p><strong>little</strong>：单词本义为「<strong>一点、少许</strong>」</p><ul><li><p><strong><code>a little</code>+<code>un.</code></strong>：表示肯定含义，即剩余的数量刚好够完成接下来要做的事</p><p>e.g. <code>There is a little milk in the fridge. You can drink that.</code>、<code>They have a little money, so they&#39;re not very poor.</code></p></li><li><p><strong><code>little</code>+<code>un.</code></strong>：表示否定含义，即剩余的数量不足以完成接下来要做的事</p><p>e.g. <code>There is little milk in the fridge. We need to buy some.</code>、<code>They have little money. They&#39;re very poor.</code></p></li></ul><p><strong>few</strong>：单词本义为「<strong>几个</strong>」</p><ul><li><p><strong><code>a few</code>+<code>cn.</code></strong>：表示肯定含义</p><p>e.g. <code>There are a few apples in the basket.</code>、<code>I&#39;ve got a few friends, so I&#39;m not lonely.</code></p></li><li><p><strong><code>few</code>+<code>cn.</code></strong>：表示否定含义</p><p>e.g. <code>There are few apples in the basket. It&#39;s nearly empty.</code>、<code>I&#39;ve got few friends. I&#39;m sad and lonely.</code></p></li></ul><hr><p><strong>had better do sth.</strong>：最好做某事</p><p><strong>advice sb. to do sth.</strong>：建议某人做某事</p></div><h2 id="lesson-111-112" tabindex="-1">Lesson 111~112 <a class="header-anchor" href="#lesson-111-112" aria-label="Permalink to &quot;Lesson 111~112&quot;">​</a></h2><div class="danger custom-block"><p class="custom-block-title">⚡本课重点</p><p><strong>形容词的比较形式有三种</strong></p><ul><li><p><strong>较高比较级</strong>：<code>more adj.</code>，表示「<strong>比...更</strong>」。<code>the most adj.</code>，表示「<strong>最...</strong>」</p><p>e.g. <code>She&#39;s more beautiful than her sister.</code>、<code>He&#39;s the most intelligent in his class.</code></p></li><li><p><strong>较低比较级</strong>：<code>less adj.</code>，表示「<strong>更少...</strong>」，但通常为了翻译时信达雅，更通俗的意思是「<strong>不如、不及</strong>」。<code>the least adj.</code>，也表示「<strong>最...</strong>」，但意思是<strong>反向的最</strong></p><p>e.g. <code>She&#39;s less beautiful than her sister.</code>、<code>He&#39;s the least intelligent in his class.</code></p></li><li><p><strong>平级比较级</strong>：<code>as adj. as</code>，表示「<strong>和...一样</strong>」</p><p>e.g. <code>She is as tall as her mother.</code></p></li></ul><hr><p><strong>总结</strong></p><table><thead><tr><th></th><th>结构</th><th>含义</th><th>例句</th></tr></thead><tbody><tr><td><b>A = B</b></td><td><code>as adj. as</code></td><td><b>和...一样</b></td><td><code>She is as tall as her mother.</code><div>她和她妈妈一样高</div></td></tr><tr><td rowspan="2"><b>A &gt; B</b></td><td><code>adj.er than</code></td><td><b>比...</b></td><td><code>She looks younger than her sister.</code><div>她看起来比她妹妹年轻</div></td></tr><tr><td><code>more adj. than</code></td><td><b>比...更</b></td><td><code>She&#39;s more beautiful than her sister.</code><div>她比她妹妹更漂亮</div></td></tr><tr><td rowspan="2"><b>A &lt; B</b></td><td><code>not as/so adj. as</code></td><td rowspan="2"><b>不如、不及</b></td><td><code>She looks not as/so young as her sister.</code><div>她看起来不如她妹妹年轻</div></td></tr><tr><td><code>less adj. than</code></td><td><code>She&#39;s less beautiful than her sister.</code><div>她不如她妹妹漂亮</div></td></tr><tr><td rowspan="3"><b>三者或以上</b></td><td><code>the adj.est 范围/从句</code></td><td rowspan="3"><b>最...</b></td><td><code>He&#39;s the tallest in his class.</code><div>他是班里个子最高的</div></td></tr><tr><td rowspan="2"><code>the most/least adj. 范围/从句</code></td><td><code>He&#39;s the most intelligent in his class.</code><div>他是班里最聪明的</div></td></tr><tr><td><code>He&#39;s the least intelligent in his class.</code><div>他是班里最不聪明的</div></td></tr><tr><td></td><td><code>adj.er and adj.er</code></td><td><b>越来越...</b></td><td><code>She is becoming more and more beautiful.</code><div>她越来越漂亮了</div></td></tr><tr><td></td><td><code>the adj.er, the adj.er</code></td><td><b>越...，越...</b></td><td><code>The more careful you are, the fewer mistakes you would make.</code><div>你越仔细,就越少出错</div></td></tr><tr><td></td><td><code>one of the adj.est</code></td><td><b>最...之一</b></td><td><code>Mr. Lee is one of the most popular teachers in our school.</code><div>李老师是我们学校最受欢迎的老师之一</div></td></tr></tbody></table></div><h2 id="lesson-113-114" tabindex="-1">Lesson 113~114 <a class="header-anchor" href="#lesson-113-114" aria-label="Permalink to &quot;Lesson 113~114&quot;">​</a></h2><div class="danger custom-block"><p class="custom-block-title">⚡本课重点</p><p><strong>not、no、none之间的关系</strong></p><ul><li><p><strong><code>not</code>+<code>any/a/an</code> 等价于 <code>no</code>+<code>n.</code></strong>，看如下例子</p><ul><li><code>I didn&#39;t see any cars in the street.</code> =&gt; <code>I saw no cars in the street.</code></li><li><code>There aren&#39;t any books on the shelves.</code> =&gt; <code>There are no books on the shelves.</code></li><li><code>I haven&#39;t got any time.</code> =&gt; <code>I&#39;ve got no time.</code></li><li><code>I haven&#39;t got any money.</code> =&gt; <code>I&#39;ve got no money.</code></li></ul></li><li><p><strong><code>no</code>+<code>n.</code> 等价于 <code>none</code></strong>。注意，<code>none</code>本身表示「<strong>一无所有</strong>」，使用时要结合上下文才能知道<code>none</code>指代什么，尽量不要单独使用。看如下例子</p><ul><li><code>We haven&#39;t got any beer.</code> =&gt; <code>We&#39;ve got no beer.</code> =&gt; <code>We&#39;ve got none.</code></li><li><code>There aren&#39;t any students.</code> =&gt; <code>There are no students.</code> =&gt; <code>There are none.</code></li></ul></li></ul><p><strong>so和neither</strong>：以<code>so</code>或<code>neither</code>开头的简短回答，必须用倒装句式。使用时注意如下三点</p><ul><li><strong>时态一致，人称一致</strong></li><li>肯定：<strong><code>so</code>+<code>助动词/情态动词/be</code>+<code>主语</code></strong></li><li>否定：<strong><code>neither</code>+<code>助动词/情态动词/be</code>+<code>主语</code></strong></li></ul><p>e.g. <code>I like ice cream.</code> =&gt; <code>So do I</code>、<code>I don&#39;t want to work.</code> =&gt; <code>Neither do I.</code></p></div><h2 id="lesson-115-116" tabindex="-1">Lesson 115~116 <a class="header-anchor" href="#lesson-115-116" aria-label="Permalink to &quot;Lesson 115~116&quot;">​</a></h2><h3 id="不定代词" tabindex="-1">不定代词 <a class="header-anchor" href="#不定代词" aria-label="Permalink to &quot;不定代词&quot;">​</a></h3><p>参考<a href="./../basic_concept.html#不定代词">基础概念中的不定代词</a></p><div class="danger custom-block"><p class="custom-block-title">⚡本课重点</p><p><strong><code>not anyone</code> 等价于 <code>no one</code></strong></p><p>e.g. <code>There isn&#39;t anyone in the room.</code> =&gt; <code>There is no one in the room.</code></p><p><strong><code>not anybody</code> 等价于 <code>nobody</code></strong></p><p>e.g. <code>There isn&#39;t anybody in the room.</code> =&gt; <code>There is nobody in the room.</code></p><p><strong><code>not anything</code> 等价于 <code>nothing</code></strong></p><p>e.g. <code>There isn&#39;t anything in the bag.</code> =&gt; <code>There is nothing in the bag.</code></p><p><strong><code>not anywhere</code> 等价于 <code>nowhere</code></strong></p><p>e.g. <code>I didn&#39;t go anywhere.</code> =&gt; <code>I went nowhere.</code></p><p><strong>规律</strong></p><ul><li>动词否定形式+<code>anyone/anybody/anything/anywhere</code></li><li>动词肯定形式+<code>no one/nobody/nothing/nowhere</code></li></ul></div><h2 id="lesson-117-118" tabindex="-1">Lesson 117~118 <a class="header-anchor" href="#lesson-117-118" aria-label="Permalink to &quot;Lesson 117~118&quot;">​</a></h2><h3 id="过去进行时" tabindex="-1">过去进行时 <a class="header-anchor" href="#过去进行时" aria-label="Permalink to &quot;过去进行时&quot;">​</a></h3><div class="danger custom-block"><p class="custom-block-title">⚡本课重点</p><p><strong>过去进行时</strong>：动作发生的时间是「<strong>过去</strong>」，动作的状态是「<strong>进行中</strong>」。核心结构是 <strong><code>was/were</code>+<code>V.ing</code></strong>，其中助动词<code>be</code>表示动作发生的时间，实义动词<code>V.ing</code>表示动作的状态</p><ul><li><p><strong>肯定句</strong>：<em>表示过去某个时间正在进行或者发生的动作、状态</em>。<strong><code>主语</code>+<code>was/were</code>+<code>V.ing</code>(+<code>其他</code>)</strong></p><p>e.g. <code>He was watching TV at 8 o&#39;clock last night.</code></p></li><li><p><strong>否定句</strong>：<em>只需在<code>be</code>的后面加上<code>not</code>即可</em>。<strong><code>主语</code>+<code>was/were</code>+<code>not</code>+<code>V.ing</code>(+<code>其他</code>)</strong></p><p>e.g. <code>He wasn&#39;t watching TV at 8 o&#39;clock last night.</code></p></li><li><p><strong>一般疑问句</strong>：<em>只需将<code>be</code>提到句首(主语前面)即可</em>。<strong><code>Was/Were</code>+<code>主语</code>+<code>V.ing</code>(+<code>其他</code>)</strong></p><p>e.g. <code>Was he watching TV at 8 o&#39;clock last night?</code></p></li><li><p><strong>特殊疑问句</strong>：<em>在一般疑问句的句首加上特殊疑问词并去掉答案</em>。<strong><code>特殊疑问词</code>+<code>was/were</code>+<code>主语</code>+<code>V.ing</code>(+<code>其他</code>)</strong></p><p>e.g. <code>He was watching TV at 8 o&#39;clock last night.</code> =&gt; <code>Was he watching TV at 8 o&#39;clock last night?</code> =&gt; <code>What was he doing at 8 o&#39;clock last night?</code></p><p><em>先把陈述句中的<code>be</code>动词提到句首得到一般疑问句，再用<code>what</code>对一般疑问句中的答案<code>watching TV</code>进行提问，并将其提到句首</em></p></li></ul><hr><p><strong>时间状语</strong>：表某个动作或完成对应的时间。在上面的例子中，<code>at 8 o&#39;clock last night</code>就是时间状语，其目的是交代实义动词<code>watching</code>所发生的时间</p><p><strong>时间状语从句</strong>：用一个句子来充当时间状语。例如下面的<code>when he was having dinner</code></p><p><strong>由<code>when</code>、<code>while</code>、<code>just as</code>引导的时间状语从句</strong></p><ul><li><p><strong>when</strong>：可以引导一般过去时、过去进行时、过去完成时。表示「<strong>当...的时候</strong>」</p><ul><li><strong>一般过去时<code>when</code>+<code>V.ed</code></strong>：<code>It was raining very heavily when I got off the train.</code></li><li><strong>一般过去时<code>when</code>+<code>was/were n./adj.</code></strong>：<code>I had known him when I was a student.</code></li><li><strong>过去进行时<code>when</code>+<code>was/were V.ing</code></strong>：<code>When I was sleeping my friend phoned me.</code></li><li><strong>过去完成时<code>when</code>+<code>had V.pp.</code></strong>：<code>They went home when they had spent all their money.</code></li></ul></li><li><p><strong>while</strong>：通常只会引导过去进行时，<em>但也存在一般过去时的可能，只是很少见</em>。表示「<strong>在...的时候</strong>(<em>强调两个动作的同时进行</em>)」</p><ul><li><strong>过去进行时<code>while</code>+<code>was/were V.ing</code></strong>：<code>While I was cooking the dinner, he was working in the room.</code></li></ul></li><li><p><strong>just as</strong>：引导过去进行时，表示「<strong>正当...的时候</strong>」</p><ul><li><strong>过去进行时<code>just as</code>+<code>was/were V.ing</code></strong>：<code>The telephone rang just as I was opening the door.</code></li></ul></li></ul></div><h2 id="lesson-119-120" tabindex="-1">Lesson 119~120 <a class="header-anchor" href="#lesson-119-120" aria-label="Permalink to &quot;Lesson 119~120&quot;">​</a></h2><h3 id="过去完成时" tabindex="-1">过去完成时 <a class="header-anchor" href="#过去完成时" aria-label="Permalink to &quot;过去完成时&quot;">​</a></h3><div class="danger custom-block"><p class="custom-block-title">⚡本课重点</p><p><strong>过去完成时</strong>：动作发生的时间是「<strong>过去</strong>」，动作的状态是「<strong>完成</strong>」。核心结构是 <strong><code>had</code>+<code>V.pp.</code></strong>，其中助动词<code>had</code>表示动作发生的时间，<code>过去分词</code>表示动作的状态。强调<strong>过去某一动作发生在另一个动作或状态之前(<em>过去的过去</em>)</strong>。它经常与<code>after</code>和<code>before</code>连用</p><ul><li><p><strong>肯定句</strong>：<em>表示过去某个时间之前已经完成的动作、状态</em>。<strong><code>主语</code>+<code>had</code>+<code>V.pp.</code>(+<code>其他</code>)</strong></p><p>e.g. <code>He had swallowed the coins.</code></p></li><li><p><strong>否定句</strong>：<em>直接在<code>had</code>的后面加上<code>not</code>即可</em>。<strong><code>主语</code>+<code>had</code>+<code>not</code>+<code>V.pp.</code>(+<code>其他</code>)</strong></p><p>e.g. <code>He hadn&#39;t swallowed the coins.</code></p></li><li><p><strong>一般疑问句</strong>：<em>只需将<code>had</code>提到句首(主语前面)即可</em>。<strong><code>Had</code>+<code>主语</code>+<code>V.pp.</code>(+<code>其他</code>)</strong></p><p>e.g. <code>Had he swallowed the coins?</code></p></li><li><p><strong>特殊疑问句</strong>：<em>在一般疑问句的句首加上特殊疑问词并去掉答案</em>。<strong><code>特殊疑问词</code>+<code>had</code>+<code>主语</code>+<code>V.pp.</code>(+<code>其他</code>)</strong></p><p>e.g. <code>He had swallowed the coins.</code> =&gt; <code>Had he swallowed the coins?</code> =&gt; <code>What had he swallowed?</code></p><p><em>先把陈述句中的<code>had</code>动词提到句首得到一般疑问句，再用<code>what</code>对一般疑问句中的答案<code>the coins</code>进行提问，并将其提到句首</em></p></li></ul><hr><p><strong>与<code>after</code>连用</strong>：<code>after A, B</code>等价于<code>B after A</code>，都表示「<strong>先A后B</strong>」。后发生的动作往往是一般过去时</p><ul><li><p><strong>after A, B</strong>：<strong>动作A完成之后再进行动作B</strong></p><p>e.g. <code>After I had watched the television, I had a bath.</code></p></li><li><p><strong>B after A</strong>：<strong>动作A完成之后再进行动作B</strong></p><p>e.g. <code>I had a bath after I had watched the television.</code></p></li></ul><p><strong>与<code>before</code>连用</strong>：<code>before B, A</code>等价于<code>A before B</code>，都表示「<strong>A在B之前</strong>」。后发生的动作往往是一般过去时</p><ul><li><p><strong>before B, A</strong>：<strong>在进行动作B之前发生了动作A</strong></p><p>e.g. <code>Before I had a bath, I had watched the television.</code></p></li><li><p><strong>A before B</strong>：<strong>在进行动作B之前发生了动作A</strong></p><p>e.g. <code>I had watched the television before I had a bath.</code></p></li></ul></div><h2 id="lesson-121-122" tabindex="-1">Lesson 121~122 <a class="header-anchor" href="#lesson-121-122" aria-label="Permalink to &quot;Lesson 121~122&quot;">​</a></h2><h3 id="定语从句" tabindex="-1">定语从句 <a class="header-anchor" href="#定语从句" aria-label="Permalink to &quot;定语从句&quot;">​</a></h3><div class="danger custom-block"><p class="custom-block-title">⚡本课重点</p><p>定语从句是一个相对较难的知识点，本节课主要先从汉语的角度来理解并构造定语从句</p><p><strong>定语</strong>：参考<a href="./../basic_concept.html#定语">基础概念中的定语</a>。类似于汉语中对某种东西进行修饰限定，<code>什么什么的</code>就是一种定语，比如<code>漂亮的女孩</code></p><p><strong>关系代词</strong>：<code>who</code>、<code>whom</code>、<code>whose</code>、<code>that</code>、<code>which</code></p><ul><li>连接主句和从句，充当连接词</li><li>在从句中做句子成分，指代主语或宾语</li><li><code>who</code>：用于指代人，进一步提供有关某人的信息。侧重于在从句中作主语</li><li><code>whom</code>：与<code>who</code>同义，作为动词或介词的宾语。只能在从句中作宾语</li><li><code>whose</code>：用于指代人或物，进一步提供信息时使用。侧重于在从句中作定语</li><li><code>that</code>：用于指代人或物，可以在从句中作主语、宾语或表语，只能引导限定性定语从句</li><li><code>which</code>：用于指代人以外的物，包括有生命或无生命的东西。可以在从句中作主语或宾语</li></ul><p><strong>定义从句</strong>：用一个句子来充当定语，去修饰限定另一个句子(<code>主句</code>)的中心词。<strong>被修饰限定的成分(<code>名词/代词</code>)叫先行词</strong>。<strong>先行词总是放在定语从句的前面</strong>，所以叫先行词</p><ul><li><p><strong>修饰人</strong>：关系代词用 <strong><code>who/whom/that</code></strong>。<strong>当先行词在从句中作主语时，只能用<code>who</code>或<code>that</code>；而作宾语时，可以用<code>who</code>、<code>whom</code>或<code>that</code>，甚至省略</strong>。在生活中，实际上人们更多是用<code>who</code></p><p><strong>e.g. 他就是昨天打电话给我的那个人</strong></p><ul><li>①分析句子可知，从句中「<strong><code>昨天打电话给我的</code></strong>」修饰限定「<strong><code>那个人</code></strong>」</li><li>②根据分析结果将这句中文拆分成两个部分，<code>He is the man.</code> 和 <code>The man called me yesterday.</code></li><li>③由于先行词 <strong><code>the man</code></strong> 在从句中<strong>作主语</strong>，所以关系代词只能用<code>who</code>或<code>that</code>，且不能省略</li><li>④最后得到完整句子 <code>He is the man who/that called me yesterday.</code></li></ul><p><strong>e.g. 他就是我昨天遇到的那个人</strong></p><ul><li>①分析句子可知，从句中「<strong><code>我昨天遇到的</code></strong>」修饰限定「<strong><code>那个人</code></strong>」</li><li>②根据分析结果将这句中文拆分成两个部分，<code>He is the man.</code> 和 <code>I met the man yesterday.</code></li><li>③由于先行词 <strong><code>the man</code></strong> 在从句中<strong>作宾语</strong>，所以关系代词可以用<code>who</code>、<code>whom</code>或<code>that</code>，甚至省略</li><li>④最后得到完整句子 <code>He is the man (who/whom/that) I met yesterday.</code></li></ul></li><li><p><strong>修饰物</strong>：关系代词用 <strong><code>which/that</code></strong>。<strong>当先行词在从句中作主语或宾语时，可以用<code>which</code>或<code>that</code>；并且作宾语时甚至还能省略</strong>。在生活中，实际上人们更多是用<code>which</code></p><p><strong>e.g. 叼着篮子的那只狗是我的</strong></p><ul><li>①分析句子可知，从句中「<strong><code>叼着篮子的</code></strong>」修饰限定「<strong><code>那只狗</code></strong>」</li><li>②根据分析结果将这句中文拆分成两个部分，<code>The dog is mine.</code> 和 <code>The dog is carrying the basket.</code></li><li>③由于先行词 <strong><code>the dog</code></strong> 在从句中<strong>作主语</strong>，所以关系代词可以用<code>which</code>或<code>that</code>，且不能省略</li><li>④最后得到完整句子 <code>The dog which/that is carrying the basket is mine.</code></li></ul><p><strong>e.g. 这就是他寄给我的信</strong></p><ul><li>①分析句子可知，从句中「<strong><code>他寄给我的</code></strong>」修饰限定「<strong><code>信</code></strong>」</li><li>②根据分析结果将这句中文拆分成两个部分，<code>This is the letter.</code> 和 <code>He sent me the letter.</code></li><li>③由于先行词 <strong><code>the letter</code></strong> 在从句中<strong>作宾语</strong>，所以关系代词可以用<code>which</code>或<code>that</code>，甚至省略</li><li>④最后得到完整句子 <code>This is the letter (which/that) he sent me.</code></li></ul></li><li><p><strong>修饰人或物</strong>：关系代词用 <strong><code>whose/that</code></strong>。<strong>当先行词在从句中作定语时，关系代词要用<code>whose</code>；当先行词为不定代词或由数词、最高级、<code>the only</code>、<code>the very</code>、<code>the same</code>、<code>all</code>所修饰，又或者是以<code>who</code>、<code>what</code>、<code>which</code>开头的疑问句时，关系代词只能用<code>that</code></strong></p><p><strong>e.g. 我朋友的母亲是一名老师</strong></p><ul><li>①分析句子可知，从句中「<strong><code>朋友的</code></strong>」修饰限定「<strong><code>母亲</code></strong>」</li><li>②根据分析结果将这句中文拆分成两个部分，<code>I have a friend.</code> 和 <code>His mother is a teacher.</code></li><li>③由于先行词 <strong><code>a friend</code></strong> 在从句中<strong>作<code>mother</code>的定语</strong>，所以关系代词要用<code>whose</code></li><li>④最后得到完整句子 <code>I have a friend whose mother is a teacher.</code></li></ul><p><strong>e.g. 你住的那个小镇叫什么名字</strong></p><ul><li>①分析句子可知，从句中「<strong><code>你住的</code></strong>」修饰限定「<strong><code>那个小镇</code></strong>」</li><li>②根据分析结果将这句中文拆分成两个部分，<code>What&#39;s the name of the town?</code> 和 <code>The town you live in.</code></li><li>③由于先行词 <strong><code>the town</code></strong> 在从句中<strong>作宾语</strong>并且是以<code>what</code>开头的疑问句，所以关系代词要用<code>that</code></li><li>④最后得到完整句子 <code>What&#39;s the name of the town that you live in?</code></li></ul></li></ul></div><h2 id="lesson-123-124" tabindex="-1">Lesson 123~124 <a class="header-anchor" href="#lesson-123-124" aria-label="Permalink to &quot;Lesson 123~124&quot;">​</a></h2><div class="danger custom-block"><p class="custom-block-title">⚡本课重点</p><p>本节课主语学习定语从句中关系代词的省略</p><p><strong>先行词是人</strong></p><ul><li><p><strong><code>who</code>+<code>动词</code></strong></p><ul><li><code>He is the man who called me yesterday.</code>，先行词在从句中作主语，<code>who</code>不能省略</li><li><code>The woman (who is) standing behind the counter served me.</code>，先行词在从句中作主语，并且从句是进行时态，这个时候<code>who</code>和<code>be</code>均可省略</li><li><code>He is the man (who) I met yesterday.</code>，先行词在从句中作宾语，<code>who</code>可以省略</li></ul></li><li><p><strong><code>whom</code>+<code>动词</code>+<code>prep.</code></strong></p><ul><li><code>The man (whom) I spoke to is my uncle.</code>，先行词在从句中作宾语，<code>whom</code>可以省略</li><li><code>The man to whom I spoke is my uncle.</code>，把介词提前的反习惯用法(<em>正常人不会这么用</em>)，这个时候<code>whom</code>不能省略</li></ul></li></ul><p><strong>先行词是物</strong></p><ul><li><p><strong><code>which</code>+<code>及物动词</code></strong></p><ul><li><code>The bus which takes us to school often breaks down.</code>，先行词在从句中作主语，<code>which</code>不能省略</li><li><code>The dog (which is) carrying the basket is mine.</code>，先行词在从句中作主语，并且从句是进行时态，这个时候<code>which</code>和<code>be</code>均可省略</li><li><code>This is the letter (which) I received yesterday.</code>，先行词在从句中作宾语，<code>which</code>可以省略</li></ul></li><li><p><strong><code>which</code>+<code>不及物动词</code>+<code>prep.</code></strong></p><ul><li><code>These are the books (which) I told you about.</code>，先行词在从句中作宾语，<code>which</code>可以省略，还可以用介词结尾</li><li><code>These are the books about which I told you.</code>，把介词提前的反习惯用法(<em>正常人不会这么用</em>)，这个时候<code>which</code>不能省略</li></ul></li></ul><p><strong>先行词是人或物</strong></p><ul><li><p><strong><code>whose</code>+<code>名词</code></strong>：先行词在从句中作定语，<code>whose</code>不能省略</p><ul><li><code>I have a friend whose mother is a teacher.</code>，关系代词<code>whose</code>指代<code>My friend&#39;s</code>，作<code>mother</code>的定语</li></ul></li><li><p><strong><code>that</code></strong>：除了适用<code>who</code>、<code>whom</code>和<code>which</code>的规则外，还有自己的特殊规则，例如先行词为不定代词或以<code>who</code>、<code>what</code>、<code>which</code>开头的疑问句，关系代词只能用<code>that</code></p><ul><li><code>What&#39;s the name of the town (that) you live in?</code>，先行词在从句中作宾语，<code>that</code>可以省略</li><li><code>The hospital is around the corner is the one (that) we are going to.</code>，先行词在从句中作表语，<code>that</code>可以省略</li></ul></li></ul><hr><p><strong>感叹句</strong>：<strong><code>what</code>+<code>a/an</code>+<code>adj.</code>+<code>名词</code></strong></p><p>e.g. <code>What a beautiful ship!</code>、<code>What an interesting program!</code></p></div><h2 id="lesson-125-126" tabindex="-1">Lesson 125~126 <a class="header-anchor" href="#lesson-125-126" aria-label="Permalink to &quot;Lesson 125~126&quot;">​</a></h2><h3 id="have-to" tabindex="-1">have to <a class="header-anchor" href="#have-to" aria-label="Permalink to &quot;have to&quot;">​</a></h3><div class="danger custom-block"><p class="custom-block-title">⚡本课重点</p><p><strong>have to</strong>：这是英语语言习惯中的一个<strong>固定搭配用法</strong>，表示客观的「<strong>必须、不得不</strong>」。它是一个复合动词，有时态的变化，变化作用于助动词<code>have</code>，而在变为否定句和疑问句时要根据不同时态的助动词来处理；<code>to</code>后面接<code>动词原形</code></p><ul><li><p><strong>一般现在时</strong>：适用主谓宾结构的一般现在时句式，三单形式也是。助动词分别是<code>do</code>和<code>does</code></p><ul><li><code>I have to leave now.</code>、<code>He has to leave now.</code></li><li><code>I don&#39;t have to leave now.</code>、<code>He doesn&#39;t have to leave now.</code></li><li><code>Do you have to leave now?</code>、<code>Does he have to leave now?</code></li><li><code>Why do you have to leave now?</code>、<code>Why does he have to leave now?</code></li></ul></li><li><p><strong>一般过去时</strong>：适用主谓宾结构的一般过去时句式，助动词是<code>did</code></p><ul><li><code>I had to walk home last night.</code></li><li><code>I didn&#39;t have to walk home last night.</code></li><li><code>Did you have to walk home last night?</code></li><li><code>Why did you have to walk home last night?</code></li></ul></li><li><p><strong>一般将来时</strong>：<code>will/shall</code>+<code>have to</code></p><ul><li><code>I will have to stay at home taday.</code></li><li><code>I won&#39;t have to stay at home taday.</code></li><li><code>Will you have to stay at home taday?</code></li><li><code>Why will you have to stay at home taday?</code></li></ul></li><li><p><strong>现在完成时</strong>：<code>have/has</code>+<code>had to</code></p><ul><li><code>I have had to wait for you two hours.</code>、<code>He has had to wait for his friend two hours.</code></li><li><code>I haven&#39;t had to wait for you two hours.</code></li><li><code>Have you had to wait for me two hours?</code></li><li><code>How long have you had to wait for me?</code></li></ul></li></ul><p><strong>have to和must的区别</strong></p><ul><li><strong><code>must</code></strong>：情态动词，没有时态变化，表示说话人主观看法。一般只能表达现在的必要性，不用来讨论过去</li><li><strong><code>have to</code></strong>：复合动词，有时态变化，表示说话人的客观需要或外界影响。可以表达过去、现在或将来的必要性</li><li><strong>否定表达完全不同</strong>：<code>mustn&#39;t</code>表示「<strong>绝对禁止</strong>」，没有商量的余地；<code>don&#39;t have to</code>表示「<strong>不必</strong>」，有得商量。<code>don&#39;t have to</code>等价于<code>don&#39;t need to</code></li><li><strong>如果想要对<code>must</code>的提问来表达「不必」，则只能用<code>needn&#39;t</code></strong></li></ul></div><h2 id="lesson-127-128" tabindex="-1">Lesson 127~128 <a class="header-anchor" href="#lesson-127-128" aria-label="Permalink to &quot;Lesson 127~128&quot;">​</a></h2><h3 id="推测的表达方式" tabindex="-1">推测的表达方式 <a class="header-anchor" href="#推测的表达方式" aria-label="Permalink to &quot;推测的表达方式&quot;">​</a></h3><p>从127~132课将会学习不同的推测表达方式</p><div class="danger custom-block"><p class="custom-block-title">⚡本课重点</p><p><strong>must be</strong>：表示根据已经了解到的信息，<strong>对当前状况进行肯定的推测</strong>，概率接近100%，意思为「<strong>一定是</strong>」</p><ul><li><p><strong><code>must be</code>+<code>adj./n.</code></strong></p><p>e.g. <code>He must be busy.</code>、<code>He must be a teacher.</code></p></li><li><p><strong><code>must be</code>+<code>V.ing</code></strong></p><p>e.g. <code>You must be joking.</code>、<code>You must be having a bath.</code></p></li><li><p><strong><code>must be</code>+<code>宾语从句</code></strong></p><p>e.g. <code>You must be the boyfriend of that girl.</code></p></li></ul><p><strong>can&#39;t be</strong>：表示根据已经了解到的信息，<strong>对当前状况进行否定的推测</strong>，概率接近0%，意思为「<strong>一定不是</strong>」</p><ul><li><p><strong><code>can&#39;t be</code>+<code>adj./n.</code></strong></p><p>e.g. <code>It can&#39;t be true.</code>、<code>He can&#39;t be a teacher.</code></p></li><li><p><strong><code>can&#39;t be</code>+<code>V.ing</code></strong></p><p>e.g. <code>They can&#39;t be working.</code></p></li><li><p><strong><code>can&#39;t</code>+<code>宾语从句</code></strong></p><p>e.g. <code>You can&#39;t be the boyfriend of that girl.</code></p></li></ul><hr><p><strong>not more than</strong>：表示「<strong>不超过</strong>」</p></div><h2 id="lesson-129-130" tabindex="-1">Lesson 129~130 <a class="header-anchor" href="#lesson-129-130" aria-label="Permalink to &quot;Lesson 129~130&quot;">​</a></h2><div class="danger custom-block"><p class="custom-block-title">⚡本课重点</p><p><strong>must have been</strong>：表示根据已经了解到的信息，<strong>对过去的状况进行肯定的推测</strong>，概率接近100%，意思为「<strong>(当时)一定是</strong>」，翻译时，根据上下文来决定是否加<strong>当时</strong></p><ul><li><p><strong><code>must have</code>+<code>V.pp.</code></strong></p><p>e.g. <code>You must have eaten my biscuits.</code></p></li><li><p><strong><code>must have been</code>+<code>adj./n.</code></strong></p><p>e.g. <code>He must have been busy.</code>、<code>He must have been a teacher.</code></p></li><li><p><strong><code>must have been</code>+<code>V.ing</code></strong></p><p>e.g. <code>They must have been having a party.</code></p></li><li><p><strong><code>must have been</code>+<code>宾语从句</code></strong></p><p>e.g. <code>You must have been the boyfriend of that girl.</code></p></li></ul><p><strong>can&#39;t have been</strong>：表示根据已经了解到的信息，<strong>对过去的状况进行否定的推测</strong>，概率接近0%，意思为「<strong>(当时)一定不是</strong>」，翻译时，根据上下文来决定是否加<strong>当时</strong></p><ul><li><p><strong><code>can&#39;t have</code>+<code>V.pp.</code></strong></p><p>e.g. <code>You can&#39;t have eaten my biscuits.</code></p></li><li><p><strong><code>can&#39;t have been</code>+<code>adj./n.</code></strong></p><p>e.g. <code>He can&#39;t have been busy.</code>、<code>He can&#39;t have been a teacher.</code></p></li><li><p><strong><code>can&#39;t have been</code>+<code>V.ing</code></strong></p><p>e.g. <code>They can&#39;t have been having a party.</code></p></li><li><p><strong><code>can&#39;t have been</code>+<code>宾语从句</code></strong></p><p>e.g. <code>You can&#39;t have been the boyfriend of that girl.</code></p></li></ul><p><strong>注意，这里的<code>have been</code>跟现在完成时没有任何关系，英语语言习惯就这样，就是个固定搭配</strong></p><hr><p><strong>do you think</strong>：用在特殊疑问句中的插入语，用来征询见解或表达看法。插入语可以位于句尾或句中，有时也可以出现在一般疑问句中</p><p>e.g. <code>Will he be late for school, do you think?</code></p><p><strong>must have been连读</strong>：发音为<code>/mʌst hæv biːn/</code>，<code>h</code>和<code>v</code>不发音</p><p><strong>can&#39;t have been连读</strong>：发音为<code>/kɑːnt hæv biːn/</code>，<code>h</code>和<code>v</code>不发音</p></div><h2 id="lesson-131-132" tabindex="-1">Lesson 131~132 <a class="header-anchor" href="#lesson-131-132" aria-label="Permalink to &quot;Lesson 131~132&quot;">​</a></h2><div class="danger custom-block"><p class="custom-block-title">⚡本课重点</p><p><strong>may和might</strong>：表示对过去、现在、将来的推测，概率不高，50%左右，意思为「<strong>可能、也许</strong>」。其否定形式为在<code>may/might</code>的后面直接加<code>not</code></p><p>虽然<code>might</code>本身是<code>may</code>的过去式，但在现代英语使用习惯中，<code>might</code>同样能用来对当前或将来状况进行推测，只是其概率比<code>may</code>稍低，并且当情况是虚拟的时候只能用<code>might</code>。</p><p><strong>对现在或将来推测</strong></p><ul><li><p><strong><code>may/might (not)</code>+<code>V.</code></strong></p><p>e.g. <code>He may (not) know the answer.</code>、<code>We might not go anywhere.</code></p></li><li><p><strong><code>may/might (not) be</code>+<code>adj./n.</code></strong></p><p>e.g. <code>They may (not) be busy.</code>、<code>She might (not) be a teacher.</code></p></li><li><p><strong><code>may/might (not) be</code>+<code>V.ing</code></strong></p><p>e.g. <code>You may (not) be joking.</code>、<code>They might (not) be having lunch.</code></p></li></ul><p><strong>对过去推测</strong></p><ul><li><p><strong><code>may/might (not) have</code>+<code>V.pp.</code></strong></p><p>e.g. <code>He may (not) have known the answer.</code>、<code>We might not have gone anywhere.</code></p></li><li><p><strong><code>may/might (not) have been</code>+<code>adj./n.</code></strong></p><p>e.g. <code>They may (not) have been busy.</code>、<code>She might (not) have been a teacher.</code></p></li><li><p><strong><code>may/might (not) have been</code>+<code>V.ing</code></strong></p><p>e.g. <code>You may (not) have been joking.</code>、<code>They might (not) have been having lunch.</code></p></li></ul><p><strong>might have been连读</strong>：发音为<code>/ˈmaɪt həv biːn/</code>，<code>h</code>不发音</p></div><h2 id="lesson-133-134" tabindex="-1">Lesson 133~134 <a class="header-anchor" href="#lesson-133-134" aria-label="Permalink to &quot;Lesson 133~134&quot;">​</a></h2><h3 id="直接引语变间接引语" tabindex="-1">直接引语变间接引语 <a class="header-anchor" href="#直接引语变间接引语" aria-label="Permalink to &quot;直接引语变间接引语&quot;">​</a></h3><div class="danger custom-block"><p class="custom-block-title">⚡本课重点</p><p>在之前的<a href="#lesson-75-76">75~76课</a>和<a href="#lesson-99-100">99~100课</a>中，主要学习了宾语从句在<strong>主句是一般现在时的用法</strong>，这时候的从句可以是任何时态</p><p><strong>当主句是一般过去时情况下，间接引语通常需要改变人称和时态</strong>，这是因为原话进行的时间永远都是早于转述的时间</p><p><strong>直接引语变间接引语</strong></p><table><thead><tr><th rowspan="2" style="text-align:center;">人称变化</th><th rowspan="2" style="text-align:center;">说明</th><th colspan="2" style="text-align:center;">直接引语</th><th colspan="2" style="text-align:center;">间接引语</th></tr><tr><th>时态</th><th>例句</th><th>时态</th><th>例句</th></tr></thead><tbody><tr><td rowspan="5"><b>一随主</b></td><td rowspan="5">引号内第一人称变间接引语后，<b>与主句主语的人称保持一致</b></td><td>一般现在时</td><td>She said, &quot;<code>I like</code> English.&quot;</td><td>一般过去时</td><td>She said <code>she liked</code> English.</td></tr><tr><td>现在进行时</td><td>She said, &quot;<code>I am studying</code> English.&quot;</td><td>过去进行时</td><td>She said <code>she was studying</code> English.</td></tr><tr><td>现在完成时</td><td>They said, &quot;<code>We have finished</code> the work.&quot;</td><td rowspan="2">过去完成时</td><td>They said <code>they had finished</code> the work.</td></tr><tr><td>一般过去时</td><td>He said to her, &quot;<code>I waited</code> for an hour.&quot;</td><td>He told her that <code>he had waited</code> for an hour.&quot;</td></tr><tr><td>一般将来时</td><td>She said, &quot;<code>I am going to study</code> English.&quot;</td><td>过去将来时</td><td>She said <code>she was going to study</code> English.</td></tr><tr><td rowspan="5"><b>二随宾</b></td><td rowspan="5">引号内第二人称变间接引语后，<b>与主句宾语的人称保持一致，如果主句没有宾语，则可以用第一人称</b></td><td>一般现在时</td><td>Tom said to Lucy, &quot;<code>You are</code> so cute.&quot;</td><td>一般过去时</td><td>Tom told Lucy <code>she was</code> so cute.</td></tr><tr><td>现在进行时</td><td>The policeman said, &quot;<code>You are driving</code> too fast.&quot;</td><td>过去进行时</td><td>The policeman said <code>I was driving</code> too fast.</td></tr><tr><td>现在完成时</td><td>She said to him, &quot;<code>You have finished your</code> job.&quot;</td><td rowspan="2">过去完成时</td><td>She told him that <code>he had finished his</code> job.</td></tr><tr><td>一般过去时</td><td>She said to him, &quot;<code>You did</code> very well.&quot;</td><td>She told him that <code>he had done</code> very well.</td></tr><tr><td>一般将来时</td><td>She said to me, &quot;I <code>am going to buy you</code> an ice cream.&quot;</td><td>过去将来时</td><td>She told me that she <code>was going to buy me</code> an ice cream.</td></tr><tr><td rowspan="5"><b>第三人称不更新</b></td><td rowspan="5">引号内第三人称变间接引语后，<b>人称保持不变</b></td><td>一般现在时</td><td>She said to me, &quot;<code>Tom is</code> the winner.&quot;</td><td>一般过去时</td><td>She told me that <code>Tom was</code> the winner.</td></tr><tr><td>现在进行时</td><td>He said, &quot;<code>She is waiting</code> for a bus.&quot;</td><td>过去进行时</td><td>He said that <code>she was waiting</code> for a bus.</td></tr><tr><td>现在完成时</td><td>He said to me, &quot;<code>They have</code> already <code>retired</code>.&quot;</td><td rowspan="2">过去完成时</td><td>He told me that <code>they had</code> already <code>retired</code>.</td></tr><tr><td>一般过去时</td><td>She said to me, &quot;<code>Jack bought</code> a new car.&quot;</td><td>She told me that <code>Jack had bought</code> a new car.</td></tr><tr><td>一般将来时</td><td>She said to me, &quot;<code>They are going to move</code> into a new flat.&quot;</td><td>过去将来时</td><td>She told me that <code>they were going to move</code> into a new flat.</td></tr></tbody></table></div><h2 id="lesson-135-136" tabindex="-1">Lesson 135~136 <a class="header-anchor" href="#lesson-135-136" aria-label="Permalink to &quot;Lesson 135~136&quot;">​</a></h2><div class="danger custom-block"><p class="custom-block-title">⚡本课重点</p><p><strong>let</strong>：表示「<strong>允许、让</strong>」。它与一般动词不同，使用结构为 <strong><code>let</code>+<code>名词/代词</code>+<code>V.</code></strong>，其中<code>V</code>表示不带<code>to</code>的动词不定式</p><p>e.g. <code>She lets her son play in the garden.</code></p><p><strong>introduce A to B</strong>：表示「<strong>把A介绍给B</strong>」</p><p>e.g. <code>He introduces me to his friend.</code></p><p><strong>当主句是一般过去时情况下，间接引语中的情态动词要用过去式</strong></p><table><thead><tr><th rowspan="2" style="text-align:center;">人称变化</th><th rowspan="2" style="text-align:center;">说明</th><th colspan="3" style="text-align:center;">直接引语</th><th colspan="3" style="text-align:center;">间接引语</th></tr><tr><th>时态</th><th>情态动词</th><th>例句</th><th>时态</th><th>情态动词</th><th>例句</th></tr></thead><tbody><tr><td rowspan="3"><b>一随主</b></td><td rowspan="3">引号内第一人称变间接引语后，<b>与主句主语的人称保持一致</b></td><td rowspan="3">一般现在时</td><td>can</td><td>She said, &quot;<code>I can</code> speak English.&quot;</td><td rowspan="3">一般过去时</td><td>could</td><td>She said <code>she could</code> speak English.</td></tr><tr><td>will</td><td>He said, &quot;<code>I will</code> do it <code>myself</code>.&quot;</td><td>would</td><td>He said <code>he would</code> do it <code>himself</code>.</td></tr><tr><td>may</td><td>He said, &quot;<code>I may</code> go with <code>you</code>.&quot;</td><td>might</td><td>He said <code>he might</code> go with <code>me</code>.</td></tr><tr><td rowspan="3"><b>二随宾</b></td><td rowspan="3">引号内第二人称变间接引语后，<b>与主句宾语的人称保持一致，如果主句没有宾语，则可以用第一人称</b></td><td rowspan="3">一般现在时</td><td>can</td><td>His mother said, &quot;<code>You can</code> watch television.&quot;</td><td rowspan="3">一般过去时</td><td>could</td><td>His mother said that <code>he could</code> watch television.</td></tr><tr><td>will</td><td>He said, &quot;<code>You will</code> win.&quot;</td><td>would</td><td>He said that <code>I would</code> win.</td></tr><tr><td>may</td><td>He said to her, &quot;<code>You may</code> be right.&quot;</td><td>might</td><td>He told her that <code>she might</code> be right.</td></tr><tr><td rowspan="3"><b>第三人称不更新</b></td><td rowspan="3">引号内第三人称变间接引语后，<b>人称保持不变</b></td><td rowspan="3">一般现在时</td><td>can</td><td>She said to me, &quot;<code>Tom can</code> swim.&quot;</td><td rowspan="3">一般过去时</td><td>could</td><td>She told me that <code>Tom could</code> swim.</td></tr><tr><td>will</td><td>She said, &quot;<code>They will</code> go to London next week.&quot;</td><td>would</td><td>She said that <code>they would</code> go to London next week.</td></tr><tr><td>may</td><td>He said to me, &quot;<code>She may</code> be 18.&quot;</td><td>might</td><td>He told me that <code>she might</code> be 18.</td></tr></tbody></table></div><h2 id="lesson-137-138" tabindex="-1">Lesson 137~138 <a class="header-anchor" href="#lesson-137-138" aria-label="Permalink to &quot;Lesson 137~138&quot;">​</a></h2><h3 id="条件从句" tabindex="-1">条件从句 <a class="header-anchor" href="#条件从句" aria-label="Permalink to &quot;条件从句&quot;">​</a></h3><div class="danger custom-block"><p class="custom-block-title">⚡本课重点</p><p><strong><code>if</code></strong>：单词本义「<strong>如果、是否</strong>」，通常用来引导一个从句</p><p><strong>条件从句</strong>：如果我们认为将来的事件是可能发生的，就可以用<code>if</code>条件从句去描述将会发生什么事或不会发生什么事。其基本结构为 <strong><code>if</code>+<code>一般现在时</code>+<code>将来时/情态助动词</code></strong>。也就是主句用将来时或情态动词，从句用一般现在时，归纳为四字诀「<strong>主将从现</strong>」</p><p>如果<code>if</code>条件从句是前半句的话，常常需要用逗号分隔；而如果是后半句的话则不需要用逗号分隔</p><ul><li><code>If it rains tomorrow, we won&#39;t go to the seaside.</code></li><li><code>I&#39;ll wash the dishes if you cook dinner。</code></li><li><code>If you&#39;re have enough money, you can buy a big house.</code></li></ul></div><h2 id="lesson-139-140" tabindex="-1">Lesson 139~140 <a class="header-anchor" href="#lesson-139-140" aria-label="Permalink to &quot;Lesson 139~140&quot;">​</a></h2><h3 id="疑问句宾语从句" tabindex="-1">疑问句宾语从句 <a class="header-anchor" href="#疑问句宾语从句" aria-label="Permalink to &quot;疑问句宾语从句&quot;">​</a></h3><div class="danger custom-block"><p class="custom-block-title">⚡本课重点</p><p>在之前的<a href="#lesson-75-76">75~76课</a>、<a href="#lesson-99-100">99~100课</a>和<a href="#lesson-133-134">133~136课</a>中所学的宾语从句全部都是<strong>陈述句做宾语从句</strong>，本节课将会学习<strong>疑问句做宾语从句</strong>的相关知识</p><table><thead><tr><th></th><th style="text-align:center;">连接词</th><th style="text-align:center;">宾语从句</th></tr></thead><tbody><tr><td rowspan="3"><b>主句</b></td><td><code>that</code>，可省略</td><td><div>陈述句</div>(肯&amp;否)</td></tr><tr><td><code>if</code>，不可省略</td><td><div>一般疑问句</div>(陈述语序)</td></tr><tr><td><code>特殊疑问词</code>，不可省略</td><td><div>特殊疑问句</div>(陈述语序)</td></tr></tbody></table><p><strong>一般疑问句宾语从句</strong>：由 <strong><code>if</code>引导的陈述语序</strong>的一般疑问句作宾语从句，其结构为 <strong><code>主句</code>+<code>if</code>+<code>宾从(一般疑问句)</code></strong></p><p>看下面几个例子，掌握一般疑问句宾语从句的转化步骤</p><p>e.g. <code>I want to know ...</code></p><ul><li>①一般疑问句：<code>Is she a teacher?</code></li><li>②把一般疑问句转为陈述语序：<code>she is a teacher</code></li><li>③给主句添加连接词<code>if</code>用来引导第二步的陈述语序：<code>I want to know if she is a teacher.</code></li></ul><hr><ul><li>①一般疑问句：<code>Does she often go shopping?</code></li><li>②把一般疑问句转为陈述语序：<code>she often goes shopping</code></li><li>③给主句添加连接词<code>if</code>用来引导第二步的陈述语序：<code>I want to know if she often goes shopping.</code></li></ul><hr><ul><li>①一般疑问句：<code>Have you lost your key?</code></li><li>②把一般疑问句转为陈述语序：<code>you have lost your key</code></li><li>③给主句添加连接词<code>if</code>用来引导第二步的陈述语序：<code>I want to know if you have lost your key.</code></li></ul><hr><ul><li>①一般疑问句：<code>Will you go to school tomorrow?</code></li><li>②把一般疑问句转为陈述语序：<code>you will go to school tomorrow</code></li><li>③给主句添加连接词<code>if</code>用来引导第二步的陈述语序：<code>I want to know if you will go to school tomorrow.</code></li></ul><hr><p><strong>特殊疑问句宾语从句</strong>：由 <strong><code>特殊疑问词</code>引导的陈述语序</strong>的特殊疑问句作宾语从句，其结构为 <strong><code>主句</code>+<code>特殊疑问词</code>+<code>宾从(特殊疑问句)</code></strong></p><p>看下面几个例子，掌握特殊疑问句宾语从句的转化步骤</p><p>e.g. <code>He wants to know ...</code></p><ul><li>①特殊疑问句：<code>What&#39;s your job?</code></li><li>②句首的特殊疑词将作为引导词维持不动，把其后面的部分转为陈述语序，人称代词根据语义进行调整：<code>what my job is</code></li><li>③将第二步得到的以特殊疑问词引导的陈述语序拼接到主句上：<code>He wants to know what my job is.</code></li></ul><hr><ul><li>①特殊疑问句：<code>When is she going to have a bath?</code></li><li>②句首的特殊疑词将作为引导词维持不动，把其后面的部分转为陈述语序：<code>when she is going to have a bath</code></li><li>③将第二步得到的以特殊疑问词引导的陈述语序拼接到主句上：<code>He wants to know when she is going to have a bath.</code></li></ul><hr><ul><li>①特殊疑问句：<code>Why does she want to see you?</code></li><li>②句首的特殊疑词将作为引导词维持不动，把其后面的部分转为陈述语序，人称代词根据语义进行调整：<code>why she wants to see me</code></li><li>③将第二步得到的以特殊疑问词引导的陈述语序拼接到主句上：<code>He wants to know why she wants to see me.</code></li></ul><hr><ul><li>①特殊疑问句：<code>Why didn&#39;t you clean the car?</code></li><li>②句首的特殊疑词将作为引导词维持不动，把其后面的部分转为陈述语序，人称代词根据语义进行调整：<code>why I didn&#39;t clean the car</code></li><li>③将第二步得到的以特殊疑问词引导的陈述语序拼接到主句上：<code>He wants to know why I didn&#39;t clean the car.</code></li></ul><hr><ul><li>①特殊疑问句：<code>How long have you lived in Nanning?</code></li><li>②句首的特殊疑词将作为引导词维持不动，把其后面的部分转为陈述语序：<code>how long I have lived in Nanning</code></li><li>③将第二步得到的以特殊疑问词引导的陈述语序拼接到主句上：<code>He wants to know how long I have lived in Nanning.</code></li></ul></div><h2 id="lesson-141-142" tabindex="-1">Lesson 141~142 <a class="header-anchor" href="#lesson-141-142" aria-label="Permalink to &quot;Lesson 141~142&quot;">​</a></h2><h3 id="被动语态" tabindex="-1">被动语态 <a class="header-anchor" href="#被动语态" aria-label="Permalink to &quot;被动语态&quot;">​</a></h3><p><strong>英语的被动语态要比汉语的简单</strong>：因为汉语中并没有限定哪些动词只能用来表示被动，相反的则是所有动词都可以表示主动或被动，这取决于你从什么角度去看待这个动词</p><p>举个栗子：<code>饭做好了</code>。短短四个字就能表达清楚意思，既省略了主语，也没有出现关键字眼<code>被</code>，这时就很难区分这是主动语态还是被动语态了，只能靠听话人自己猜。如果从说话人的角度出发，那么很大概率说话人就是<code>做饭</code>这一动作的主语，这时就是汉语中的主动语态。而如果你的关注点在<code>饭</code>，那么这时就是被动语态，此时<code>饭</code>作为主语，它是可能是被说话人或其他某个人给做出来的，至于是谁做的并不在乎</p><div class="danger custom-block"><p class="custom-block-title">⚡本课重点</p><p>英语动词也有<strong>主动语态</strong>和<strong>被动语态</strong>之分。在主动句中，动词的主语是执行动作的人或物；而在被动句中，主语则是动作的承受者。换言之，<strong>就是把主动句中的「直接宾语」变成了「主语」</strong></p><p><strong>主动语态</strong>：这里特指的是主谓宾结构，即 <strong><code>主语</code>+<code>V</code>+<code>宾语</code></strong>，其中的动词基本都是及物动词，因为其后面必须跟宾语</p><p><strong>被动语态</strong>：当不知道或没有必要指出动作的执行者时，常用被动语态，把主动句中的「<strong>直接宾语</strong>」转为「<strong>主语</strong>」即可，其核心结构为 <strong><code>be</code>+<code>V.pp.</code></strong>，过去分词不一定指过去。被动语态可以避免用不明确的词作主语，或是将重点放在事件本身而不是造成该事件的人或物上，强调的是动作的承受者</p><ul><li><p><strong>肯定句</strong>：<strong><code>主语</code>+<code>be</code>+<code>V.pp.</code>(+<code>其他</code>)</strong></p><p>e.g. <code>My phone was made in China.</code></p></li><li><p><strong>否定句</strong>：<em>只需在<code>be</code>的后面加上<code>not</code>即可</em>。<strong><code>主语</code>+<code>be</code>+<code>not</code>+<code>V.pp.</code>(+<code>其他</code>)</strong></p><p>e.g. <code>My phone wasn’t made in China.</code></p></li><li><p><strong>一般疑问句</strong>：<em>只需将<code>be</code>提到句首(主语前面)即可</em>。<strong><code>Be</code>+<code>主语</code>+<code>V.pp.</code>(+<code>其他</code>)</strong></p><p>e.g. <code>Was your phone made in China?</code></p></li><li><p><strong>特殊疑问句</strong>：<em>在一般疑问句的句首加上特殊疑问词并去掉答案</em>。<strong><code>特殊疑问词</code>+<code>be</code>+<code>主语</code>+<code>V.pp.</code>(+<code>其他</code>)</strong></p><p>e.g. <code>My phone was made in China.</code> =&gt; <code>Was your phone made in China?</code> =&gt; <code>Where was your phone made?</code></p><p><em>先把陈述句中的<code>be</code>动词提到句首得到一般疑问句，再用<code>where</code>对一般疑问句中的答案<code>in China</code>进行提问，并将其提到句首</em></p></li></ul><p><strong>八种常见的被动语态结构</strong></p><table><thead><tr><th>时态</th><th>结构</th><th>例句</th></tr></thead><tbody><tr><td>一般现在时</td><td><strong><code>am/is/are</code>+<code>V.pp.</code></strong></td><td><code>The room is aired regularly.</code></td></tr><tr><td>一般过去时</td><td><strong><code>was/were</code>+<code>V.pp.</code></strong></td><td><code>This house was built a hundred years ago.</code></td></tr><tr><td>一般将来时</td><td><strong><code>will/shall</code>+<code>be</code>+<code>V.pp.</code></strong></td><td><code>The floor will be swept soon.</code></td></tr><tr><td>现在进行时</td><td><strong><code>am/is/are</code>+<code>being</code>+<code>V.pp.</code></strong></td><td><code>The rooms are being painted.</code></td></tr><tr><td>过去进行时</td><td><strong><code>was/were</code>+<code>being</code>+<code>V.pp.</code></strong></td><td><code>The house was being built at this time last year.</code></td></tr><tr><td>现在完成时</td><td><strong><code>have/has</code>+<code>been</code>+<code>V.pp.</code></strong></td><td><code>The basket has already been emptied.</code></td></tr><tr><td>过去完成时</td><td><strong><code>had</code>+<code>been</code>+<code>V.pp.</code></strong></td><td><code>He had been considered to be a greater leader.</code></td></tr><tr><td>情态动词</td><td><strong><code>情态动词</code>+<code>be</code>+<code>V.pp.</code></strong></td><td><code>Your room must be cleaned every day.</code></td></tr></tbody></table></div><h2 id="lesson-143-144" tabindex="-1">Lesson 143~144 <a class="header-anchor" href="#lesson-143-144" aria-label="Permalink to &quot;Lesson 143~144&quot;">​</a></h2><div class="danger custom-block"><p class="custom-block-title">⚡本课重点</p><p>本节课主要讲的是<strong>一般将来时</strong>和<strong>现在完成时</strong>的被动语态，但由于已经在<a href="#lesson-141-142">141~142课</a>进行了概括性总结，所以这里就不再重复了</p><p><strong>A be surrounded by B</strong>：表示「<strong>A被B包围</strong>」</p></div>',184),n=[s];function a(r,l,i,g,h,p){return o(),d("div",null,n)}const b=e(t,[["render",a]]);export{m as __pageData,b as default};
